<#
Firestone2Green

Purpose:
  Keep Firestone/Overwolf in an offline, signed, non-mutated state:
  - stop Overwolf before any change
  - verify/restore the signed Firestone package from app.opk
  - remove known experimental patch leftovers
  - quarantine downloaded web/code caches
  - block outbound network for every detected Overwolf executable
  - add exact-domain hosts blocks for Firestone/Overwolf/cloud/ad endpoints found locally
  - generate a JSON report
  - optionally install a scheduled task so the shield is re-applied after updates/logon

No internet access is used by this script.
#>

[CmdletBinding()]
param(
  [ValidateSet('Apply','Verify','Restore','Monitor','Launch','Auth','LaunchAuth','AutoAuth','WatchFirestone','DataOnline','AuthOnlyOnline','InstallTask','InstallDataOnlineTask','InstallAuthOnlyOnlineTask','InstallAutoAuthTask','RemoveTask','All')]
  [string]$Mode = 'Apply',

  [string]$AppId = 'lnknbakkpommmjjdnelmfbjjdbocfpnpbkijjnob',
  [string]$AppName = 'Firestone',
  [string]$OverwolfRoot = '',
  [string]$CommonOverwolfRoot = "${env:ProgramFiles(x86)}\Common Files\Overwolf",
  [string]$ReportDir = "$PSScriptRoot\FirestoneOfflineReports",
  [string]$FirewallGroup = 'Firestone Offline Block',
  [string]$TaskName = 'Firestone2Green',
  [int]$AutomationPort = 18765,
  [string]$AuthPlanId = 'premium-annual',
  [string]$AvatarImagePath = '',

  [switch]$NoKill,
  [switch]$SkipHosts,
  [switch]$SkipCacheQuarantine,
  [int]$MonitorSeconds = 20
)

$ErrorActionPreference = 'Stop'

# Force UTF-8 for redirected PowerShell output so the WinForms log does not show mojibake.
try {
  $Script:Utf8NoBom = New-Object System.Text.UTF8Encoding -ArgumentList $false
  [Console]::OutputEncoding = $Script:Utf8NoBom
  [Console]::InputEncoding = $Script:Utf8NoBom
  $OutputEncoding = $Script:Utf8NoBom
} catch {}

$ScriptDir = if ($PSScriptRoot) { $PSScriptRoot } elseif ($PSCommandPath) { Split-Path -Parent $PSCommandPath } else { (Get-Location).Path }
if ([string]::IsNullOrWhiteSpace($ReportDir) -or $ReportDir -eq '\FirestoneOfflineReports') {
  $ReportDir = Join-Path $ScriptDir 'FirestoneOfflineReports'
}
if ([string]::IsNullOrWhiteSpace($AvatarImagePath)) {
  $candidateAvatar = Join-Path (Split-Path -Parent $ScriptDir) 'assets\avatar.jpg'
  if (Test-Path -LiteralPath $candidateAvatar) {
    $AvatarImagePath = $candidateAvatar
  } else {
    $AvatarImagePath = Join-Path $ScriptDir 'avatar.jpg'
  }
}
$Script:EmbeddedAvatarDataUrl = @'
data:image/jpeg;base64,
'@


function Set-State([System.Collections.IDictionary]$State, [string]$Key, $Value) {
  $State[$Key] = $Value
}

function Write-Step([string]$Message) {
  Write-Host ("`n==> " + $Message) -ForegroundColor Cyan
}

function Test-IsAdmin {
  $identity = [Security.Principal.WindowsIdentity]::GetCurrent()
  $principal = [Security.Principal.WindowsPrincipal]::new($identity)
  return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Assert-Admin([string]$Why) {
  if (-not (Test-IsAdmin)) {
    throw "需要管理员权限：$Why。请右键以管理员运行 Firestone2Green.exe。"
  }
}

function New-Directory([string]$Path) {
  if (-not (Test-Path -LiteralPath $Path)) {
    New-Item -ItemType Directory -Path $Path -Force | Out-Null
  }
  return (Resolve-Path -LiteralPath $Path).Path
}

function Get-TimeStamp {
  return (Get-Date -Format 'yyyyMMdd_HHmmss')
}

function Resolve-ExistingPath([string]$Path) {
  if (Test-Path -LiteralPath $Path) {
    return (Resolve-Path -LiteralPath $Path).Path
  }
  return $null
}

function Test-SkipSearchDirectory([string]$Name) {
  if ([string]::IsNullOrWhiteSpace($Name)) { return $false }
  $n = $Name.ToLowerInvariant()
  return $n -in @('$recycle.bin','system volume information','windows','winreagent','recovery','node_modules','.git','package cache')
}

function Find-OverwolfLauncherUnder {
  param(
    [string]$Root,
    [int]$MaxDepth = 4,
    [int]$MaxDirs = 8000
  )
  if ([string]::IsNullOrWhiteSpace($Root) -or -not (Test-Path -LiteralPath $Root -PathType Container)) { return $null }
  $queue = New-Object System.Collections.Queue
  $queue.Enqueue([pscustomobject]@{ Path = (Resolve-Path -LiteralPath $Root).Path; Depth = 0 })
  $visited = 0
  while ($queue.Count -gt 0 -and $visited -lt $MaxDirs) {
    $node = $queue.Dequeue()
    $visited++
    try {
      foreach ($exeName in @('OverwolfLauncher.exe', 'Overwolf.exe')) {
        $direct = Join-Path $node.Path $exeName
        if (Test-Path -LiteralPath $direct -PathType Leaf) {
          return (Resolve-Path -LiteralPath $direct).Path
        }
      }
    } catch {}
    if ([int]$node.Depth -ge $MaxDepth) { continue }
    try {
      Get-ChildItem -LiteralPath $node.Path -Directory -ErrorAction SilentlyContinue | ForEach-Object {
        if (-not (Test-SkipSearchDirectory $_.Name)) {
          $queue.Enqueue([pscustomobject]@{ Path = $_.FullName; Depth = ([int]$node.Depth + 1) })
        }
      }
    } catch {}
  }
  return $null
}

function ConvertTo-ExecutablePathFromCommand([string]$Command) {
  if ([string]::IsNullOrWhiteSpace($Command)) { return $null }
  $cmd = [Environment]::ExpandEnvironmentVariables($Command.Trim())
  if ($cmd.StartsWith([string][char]34)) {
    $end = $cmd.IndexOf([char]34, 1)
    if ($end -gt 1) { return $cmd.Substring(1, $end - 1) }
  }
  $idx = $cmd.IndexOf('.exe', [StringComparison]::OrdinalIgnoreCase)
  if ($idx -ge 0) { return $cmd.Substring(0, $idx + 4).Trim().Trim([char[]]@([char]34)) }
  return $cmd.Trim().Trim([char[]]@([char]34))
}

function ConvertTo-OverwolfRootCandidate([string]$Candidate) {
  if ([string]::IsNullOrWhiteSpace($Candidate)) { return $null }
  try {
    $p = [Environment]::ExpandEnvironmentVariables($Candidate.Trim().Trim([char[]]@([char]34)))
    if (Test-Path -LiteralPath $p -PathType Leaf) {
      $leafName = [IO.Path]::GetFileName($p)
      if ($leafName.Equals('OverwolfLauncher.exe', [StringComparison]::OrdinalIgnoreCase) -or
          $leafName.Equals('Overwolf.exe', [StringComparison]::OrdinalIgnoreCase)) {
        return (Resolve-Path -LiteralPath (Split-Path -Parent $p)).Path
      }
      return $null
    }
    if (Test-Path -LiteralPath $p -PathType Container) {
      $resolved = (Resolve-Path -LiteralPath $p).Path.TrimEnd('\')
      foreach ($exeName in @('OverwolfLauncher.exe', 'Overwolf.exe')) {
        $direct = Join-Path $resolved $exeName
        if (Test-Path -LiteralPath $direct -PathType Leaf) { return $resolved }
      }
      $found = Find-OverwolfLauncherUnder -Root $resolved -MaxDepth 3 -MaxDirs 1200
      if ($found) { return (Split-Path -Parent $found) }
    }
  } catch {}
  return $null
}

function Resolve-OverwolfRoot {
  param(
    [string]$RequestedRoot,
    [switch]$Deep
  )
  $candidates = New-Object System.Collections.Generic.List[string]
  function Add-Candidate([string]$Value) {
    if (-not [string]::IsNullOrWhiteSpace($Value) -and -not $candidates.Contains($Value)) { $candidates.Add($Value) }
  }

  Add-Candidate $RequestedRoot
  Add-Candidate $CommonOverwolfRoot
  Add-Candidate (Join-Path $env:LOCALAPPDATA 'Overwolf')
  Add-Candidate (Join-Path $env:ProgramFiles 'Overwolf')
  if (${env:ProgramFiles(x86)}) { Add-Candidate (Join-Path ${env:ProgramFiles(x86)} 'Overwolf') }
  if (${env:ProgramFiles(x86)}) { Add-Candidate (Join-Path ${env:ProgramFiles(x86)} 'Common Files\Overwolf') }

  try {
    Get-CimInstance Win32_Process -ErrorAction SilentlyContinue |
      Where-Object { $_.Name -in @('Overwolf.exe','OverwolfLauncher.exe') -and $_.ExecutablePath } |
      ForEach-Object { Add-Candidate $_.ExecutablePath }
  } catch {}

  foreach ($keyPath in @(
      'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run',
      'HKLM:\Software\Microsoft\Windows\CurrentVersion\Run',
      'HKLM:\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Run'
    )) {
    try {
      if (Test-Path $keyPath) {
        $props = Get-ItemProperty -Path $keyPath -ErrorAction SilentlyContinue
        foreach ($prop in $props.PSObject.Properties) {
          $value = [string]$prop.Value
          if ($value -match '(?i)overwolf') { Add-Candidate (ConvertTo-ExecutablePathFromCommand $value) }
        }
      }
    } catch {}
  }

  foreach ($keyPath in @(
      'HKCU:\Software\Microsoft\Windows\CurrentVersion\Uninstall',
      'HKCU:\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall',
      'HKLM:\Software\Microsoft\Windows\CurrentVersion\Uninstall',
      'HKLM:\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall'
    )) {
    try {
      if (Test-Path $keyPath) {
        Get-ChildItem -Path $keyPath -ErrorAction SilentlyContinue | ForEach-Object {
          try {
            $app = Get-ItemProperty -Path $_.PSPath -ErrorAction SilentlyContinue
            if ([string]$app.DisplayName -match '(?i)Overwolf') {
              Add-Candidate ([string]$app.InstallLocation)
              Add-Candidate (ConvertTo-ExecutablePathFromCommand ([string]$app.DisplayIcon))
              Add-Candidate (ConvertTo-ExecutablePathFromCommand ([string]$app.UninstallString))
            }
          } catch {}
        }
      }
    } catch {}
  }

  try {
    foreach ($drive in [IO.DriveInfo]::GetDrives()) {
      if (-not $drive.IsReady -or $drive.DriveType -ne [IO.DriveType]::Fixed) { continue }
      Add-Candidate (Join-Path $drive.RootDirectory.FullName 'overwolf')
      Add-Candidate (Join-Path $drive.RootDirectory.FullName 'Overwolf')
      Add-Candidate (Join-Path $drive.RootDirectory.FullName 'Program Files\Overwolf')
      Add-Candidate (Join-Path $drive.RootDirectory.FullName 'Program Files (x86)\Overwolf')
      Add-Candidate (Join-Path $drive.RootDirectory.FullName 'Program Files (x86)\Common Files\Overwolf')
    }
  } catch {}

  foreach ($candidate in $candidates) {
    $root = ConvertTo-OverwolfRootCandidate $candidate
    if ($root) { return $root }
  }

  if ($Deep) {
    $deepRoots = New-Object System.Collections.Generic.List[string]
    foreach ($r in @($env:LOCALAPPDATA, $env:ProgramFiles, ${env:ProgramFiles(x86)})) {
      if ($r -and (Test-Path -LiteralPath $r -PathType Container) -and -not $deepRoots.Contains($r)) { $deepRoots.Add($r) }
    }
    try {
      foreach ($drive in [IO.DriveInfo]::GetDrives()) {
        if ($drive.IsReady -and $drive.DriveType -eq [IO.DriveType]::Fixed -and -not $deepRoots.Contains($drive.RootDirectory.FullName)) {
          $deepRoots.Add($drive.RootDirectory.FullName)
        }
      }
    } catch {}
    foreach ($rootDir in $deepRoots) {
      $found = Find-OverwolfLauncherUnder -Root $rootDir -MaxDepth 6 -MaxDirs 35000
      if ($found) { return (Split-Path -Parent $found) }
    }
  }
  return $null
}

function Get-OverwolfLauncherPath {
  $root = Resolve-OverwolfRoot -RequestedRoot $OverwolfRoot -Deep
  if (-not $root) {
    throw '未找到 Overwolf 启动器。请在 Firestone2Green 界面点击“自动搜索”或“选择路径”，选择包含 OverwolfLauncher.exe 或 Overwolf.exe 的目录后重试。'
  }
  $script:OverwolfRoot = $root
  $launcher = Join-Path $root 'OverwolfLauncher.exe'
  if (-not (Test-Path -LiteralPath $launcher -PathType Leaf)) {
    $launcher = Join-Path $root 'Overwolf.exe'
  }
  if (-not (Test-Path -LiteralPath $launcher -PathType Leaf)) {
    $foundLauncher = Find-OverwolfLauncherUnder -Root $root -MaxDepth 3 -MaxDirs 1200
    if ($foundLauncher) {
      $launcher = $foundLauncher
      $script:OverwolfRoot = Split-Path -Parent $foundLauncher
    }
  }
  if (-not (Test-Path -LiteralPath $launcher -PathType Leaf)) {
    throw "未找到启动器：$root 下不存在 OverwolfLauncher.exe 或 Overwolf.exe"
  }
  return (Resolve-Path -LiteralPath $launcher).Path
}

$resolvedOverwolfRoot = Resolve-OverwolfRoot -RequestedRoot $OverwolfRoot
if ($resolvedOverwolfRoot) { $OverwolfRoot = $resolvedOverwolfRoot }

function Assert-PathUnderRoot([string]$Path, [string]$Root) {
  $resolvedPath = Resolve-ExistingPath $Path
  $resolvedRoot = Resolve-ExistingPath $Root
  if (-not $resolvedPath) { throw "路径不存在：$Path" }
  if (-not $resolvedRoot) { throw "根路径不存在：$Root" }
  $rootPrefix = $resolvedRoot.TrimEnd('\') + '\'
  if (($resolvedPath -ne $resolvedRoot) -and (-not $resolvedPath.StartsWith($rootPrefix, [StringComparison]::OrdinalIgnoreCase))) {
    throw "拒绝操作越界路径：$resolvedPath 不在 $resolvedRoot 下"
  }
  return $resolvedPath
}

function Stop-OverwolfProcesses {
  Write-Step '停止 Overwolf/Firestone 进程'
  $protectedIds = New-Object 'System.Collections.Generic.HashSet[int]'
  [void]$protectedIds.Add([int]$PID)
  try {
    $selfProc = Get-CimInstance Win32_Process -Filter "ProcessId=$PID" -ErrorAction SilentlyContinue
    if ($selfProc -and $selfProc.ParentProcessId) { [void]$protectedIds.Add([int]$selfProc.ParentProcessId) }
  } catch {}
  $targets = @(Get-CimInstance Win32_Process -ErrorAction SilentlyContinue | Where-Object {
    if ($protectedIds.Contains([int]$_.ProcessId)) { return $false }
    $name = [IO.Path]::GetFileNameWithoutExtension([string]$_.Name)
    $cmd = [string]$_.CommandLine
    if ($name -eq 'Firestone2Green') { return $false }
    ($name -like '*Overwolf*') -or
    ($name -like 'ow-*') -or
    ($cmd -like '*Firestone - *')
  })
  if (-not $targets) {
    Write-Host '未发现运行中的 Overwolf/Firestone 进程。'
    return @()
  }
  $snapshot = $targets | Select-Object @{n='Id';e={$_.ProcessId}}, @{n='ProcessName';e={[IO.Path]::GetFileNameWithoutExtension([string]$_.Name)}}, @{n='Path';e={$_.ExecutablePath}}
  $snapshot | Format-Table -AutoSize | Out-Host
  foreach ($target in $targets) {
    Stop-Process -Id $target.ProcessId -Force -ErrorAction SilentlyContinue
  }
  Start-Sleep -Seconds 2
  return $snapshot
}

function Get-FirestoneVersionRoot {
  param([string]$AppId)
  $base = Join-Path $env:LOCALAPPDATA "Overwolf\Extensions\$AppId"
  if (-not (Test-Path -LiteralPath $base)) {
    throw "未找到 Firestone 扩展目录：$base。可能只安装了 Overwolf（狼头），还没有安装 Firestone。请先在 Overwolf 中安装并正常打开一次 Firestone，等它下载完成后再运行 Firestone2Green。"
  }
  $dirs = Get-ChildItem -LiteralPath $base -Directory -ErrorAction Stop
  if (-not $dirs) {
    throw "Firestone 扩展目录下没有版本目录：$base。可能 Firestone 还没下载/更新完成。请先正常打开一次 Firestone，等待 Overwolf 安装完成后再运行 Firestone2Green。"
  }
  # Prefer newest write time; version folder names are not guaranteed to be strict SemVer.
  return ($dirs | Sort-Object LastWriteTime -Descending | Select-Object -First 1).FullName
}

function Get-OpkPathForVersion {
  param([string]$AppId, [string]$VersionName)
  $opk = Join-Path $env:LOCALAPPDATA "Overwolf\PackagesCache\$AppId\$VersionName\app.opk"
  if (Test-Path -LiteralPath $opk) { return (Resolve-Path -LiteralPath $opk).Path }
  return $null
}

function Get-VerifiedHashMap {
  param([string]$VersionRoot)
  $verified = Join-Path $VersionRoot '_metadata\verified_contents.json'
  if (-not (Test-Path -LiteralPath $verified)) {
    throw "未找到签名校验文件：$verified"
  }
  $json = Get-Content -LiteralPath $verified -Raw -Encoding UTF8 | ConvertFrom-Json
  $map = @{}
  foreach ($prop in $json.hashes.PSObject.Properties) {
    $map[$prop.Name] = [string]$prop.Value
  }
  return $map
}

function Test-FirestoneIntegrity {
  param([string]$VersionRoot)
  Write-Step "校验 Firestone 签名文件 hash：$VersionRoot"
  $hashes = Get-VerifiedHashMap -VersionRoot $VersionRoot
  $missing = New-Object System.Collections.Generic.List[string]
  $mismatch = New-Object System.Collections.Generic.List[object]
  $checked = 0
  foreach ($rel in $hashes.Keys) {
    $path = Join-Path $VersionRoot ($rel -replace '/', '\')
    if (-not (Test-Path -LiteralPath $path)) {
      $missing.Add($rel)
      continue
    }
    $actual = (Get-FileHash -LiteralPath $path -Algorithm SHA256).Hash.ToLowerInvariant()
    $expected = $hashes[$rel].ToLowerInvariant()
    $checked++
    if ($actual -ne $expected) {
      $mismatch.Add([pscustomobject]@{ path = $rel; expected = $expected; actual = $actual })
    }
  }
  $ok = ($missing.Count -eq 0 -and $mismatch.Count -eq 0)
  if ($ok) {
    Write-Host "签名文件完整：$checked 个文件匹配。"
  } else {
    Write-Warning "签名文件异常：missing=$($missing.Count), mismatch=$($mismatch.Count)"
  }
  $missingArray = @()
  foreach ($item in $missing) { $missingArray += [string]$item }
  $mismatchArray = @()
  foreach ($item in $mismatch) { $mismatchArray += $item }
  return [pscustomobject]@{
    ok = $ok
    checked = $checked
    missing = $missingArray
    mismatches = $mismatchArray
  }
}

function Restore-FirestoneFromOpk {
  param([string]$VersionRoot, [string]$AppId, [string]$BackupRoot)

  $versionName = Split-Path -Leaf $VersionRoot
  $opk = Get-OpkPathForVersion -AppId $AppId -VersionName $versionName
  if (-not $opk) {
    throw "无法恢复：未找到 OPK 缓存：$env:LOCALAPPDATA\Overwolf\PackagesCache\$AppId\$versionName\app.opk"
  }

  Write-Step "从签名 OPK 恢复 Firestone：$opk"
  $extBase = Join-Path $env:LOCALAPPDATA "Overwolf\Extensions\$AppId"
  $resolvedVersion = Assert-PathUnderRoot -Path $VersionRoot -Root $extBase
  $backupDest = Join-Path $BackupRoot ("modified_$versionName")
  if (Test-Path -LiteralPath $backupDest) {
    $backupDest = Join-Path $BackupRoot ("modified_${versionName}_" + (Get-TimeStamp))
  }
  Move-Item -LiteralPath $resolvedVersion -Destination $backupDest -Force
  Write-Host "已备份被替换目录：$backupDest"

  New-Item -ItemType Directory -Path $resolvedVersion -Force | Out-Null
  $tmpZip = Join-Path $env:TEMP ("firestone_app_$versionName.zip")
  Copy-Item -LiteralPath $opk -Destination $tmpZip -Force
  Expand-Archive -LiteralPath $tmpZip -DestinationPath $resolvedVersion -Force
  Remove-Item -LiteralPath $tmpZip -Force -ErrorAction SilentlyContinue
  Write-Host "已恢复到：$resolvedVersion"
}

function Remove-KnownPatchLeftovers {
  param([string]$VersionRoot)
  Write-Step '清理已知实验补丁残留'
  $leftovers = @(
    (Join-Path $VersionRoot 'Files\firestone-offline-guard.js')
  )
  $removed = @()
  foreach ($item in $leftovers) {
    if (Test-Path -LiteralPath $item) {
      Remove-Item -LiteralPath $item -Force
      $removed += $item
      Write-Host "已删除：$item"
    }
  }
  if (-not $removed) { Write-Host '未发现残留文件。' }
  return $removed
}

function Get-OverwolfExecutableRoots {
  param([string]$OverwolfRoot, [string]$CommonOverwolfRoot)
  $roots = New-Object System.Collections.Generic.List[string]
  foreach ($root in @(
      $OverwolfRoot,
      $CommonOverwolfRoot,
      (Join-Path $env:LOCALAPPDATA 'Overwolf'),
      (Join-Path $env:ProgramFiles 'Overwolf'),
      (Join-Path ${env:ProgramFiles(x86)} 'Overwolf')
    )) {
    if ($root -and (Test-Path -LiteralPath $root)) {
      $resolved = (Resolve-Path -LiteralPath $root).Path
      if (-not $roots.Contains($resolved)) { $roots.Add($resolved) }
    }
  }
  return @($roots)
}

function Get-OverwolfExecutables {
  param([string[]]$Roots)
  $seen = @{}
  $items = New-Object System.Collections.Generic.List[string]
  foreach ($root in $Roots) {
    Get-ChildItem -LiteralPath $root -Recurse -Filter '*.exe' -File -ErrorAction SilentlyContinue | ForEach-Object {
      $full = $_.FullName
      if (-not $seen.ContainsKey($full.ToLowerInvariant())) {
        $seen[$full.ToLowerInvariant()] = $true
        $items.Add($full)
      }
    }
  }
  return @($items | Sort-Object)
}

function Set-OverwolfFirewallBlock {
  param([string]$Group, [string[]]$ExePaths)
  Write-Step "重建出站防火墙阻断规则：$Group"
  Get-NetFirewallRule -Group $Group -ErrorAction SilentlyContinue | Remove-NetFirewallRule -ErrorAction SilentlyContinue
  $created = New-Object System.Collections.Generic.List[string]
  foreach ($exe in $ExePaths) {
    if (-not (Test-Path -LiteralPath $exe)) { continue }
    $name = "Firestone Offline Block - $(Split-Path -Leaf $exe) - $([guid]::NewGuid().ToString('N').Substring(0,8))"
    New-NetFirewallRule -DisplayName $name -Group $Group -Direction Outbound -Action Block -Program $exe -Profile Any -Enabled True | Out-Null
    $created.Add($exe)
  }
  Write-Host "已创建阻断规则：$($created.Count)"
  return @($created)
}

function Get-RemoteHostsFromLocalApp {
  param([string]$VersionRoot)
  Write-Step '从本地包提取 Firestone/Overwolf 云端域名'
  $hosts = New-Object System.Collections.Generic.HashSet[string]([StringComparer]::OrdinalIgnoreCase)
  $known = @(
    'api.overwolf.com',
    'apps.overwolf.com',
    'apps.overwolfcdn.com',
    'content.overwolf.com',
    'subscriptions-api.overwolf.com',
    'static.firestoneapp.com',
    'static.zerotoheroes.com',
    'checkout.tebex.io',
    'cdn.jsdelivr.net',
    'fonts.gstatic.com',
    'fonts.googleapis.com'
  )
  foreach ($h in $known) { [void]$hosts.Add($h) }

  $interesting = '(overwolf|firestone|zerotoheroes|lambda-url|tebex|jsdelivr|gstatic|googleapis|sascdn|rubiconproject|pubmatic|adnxs|doubleclick|googlesyndication|amazon-adsystem|id5|arcspan)'
  $files = Get-ChildItem -LiteralPath $VersionRoot -Recurse -File -Include *.js,*.html,*.json,*.css -ErrorAction SilentlyContinue
  foreach ($file in $files) {
    try {
      $text = Get-Content -LiteralPath $file.FullName -Raw -Encoding UTF8 -ErrorAction Stop
    } catch {
      continue
    }
    foreach ($m in [regex]::Matches($text, 'https?://([^/''")\s\\]+)', [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)) {
      $remoteHost = $m.Groups[1].Value.Trim().ToLowerInvariant()
      $remoteHost = $remoteHost -replace ':\d+$',''
      $remoteHost = $remoteHost -replace '^\*\.',''
      if ($remoteHost -match $interesting) {
        [void]$hosts.Add($remoteHost)
      }
    }
  }
  $result = @($hosts | Sort-Object)
  Write-Host "提取/内置域名数：$($result.Count)"
  return $result
}

function Set-HostsBlock {
  param([string[]]$Hosts)
  Write-Step '写入 hosts 精确域名阻断'
  $hostsPath = Join-Path $env:SystemRoot 'System32\drivers\etc\hosts'
  $begin = '# Firestone2Green BEGIN'
  $end = '# Firestone2Green END'
  $content = ''
  if (Test-Path -LiteralPath $hostsPath) {
    $content = Get-Content -LiteralPath $hostsPath -Raw -ErrorAction Stop
  }
  if ($null -eq $content) { $content = '' }
  $escapedBegin = [regex]::Escape($begin)
  $escapedEnd = [regex]::Escape($end)
  $content = [regex]::Replace($content, "(?ms)\r?\n?$escapedBegin.*?$escapedEnd\r?\n?", "`r`n")
  $blockLines = New-Object System.Collections.Generic.List[string]
  $blockLines.Add($begin)
  foreach ($h in ($Hosts | Sort-Object -Unique)) {
    if ($h -match '^[a-z0-9.-]+$') {
      $blockLines.Add("0.0.0.0 $h # Firestone2Green")
    }
  }
  $blockLines.Add($end)
  $newContent = $content.TrimEnd() + "`r`n`r`n" + (($blockLines -join "`r`n")) + "`r`n"
  $currentNormalized = ''
  if (Test-Path -LiteralPath $hostsPath) {
    try { $currentNormalized = (Get-Content -LiteralPath $hostsPath -Raw -ErrorAction Stop) } catch { $currentNormalized = '' }
  }
  if ($currentNormalized -eq $newContent) {
    Write-Host "hosts 阻断段无变化，跳过写入。"
  } else {
    [System.IO.File]::WriteAllText($hostsPath, $newContent, [System.Text.Encoding]::ASCII)
  }
  Write-Host "hosts 已阻断：$($blockLines.Count - 2) 个域名"
}

function Get-DataOnlineBlockedHosts {
  param([string[]]$Hosts)
  # DataOnline allows Firestone static game/card/i18n data while keeping known
  # subscription, membership-integrity, Lambda, Overwolf platform update/API,
  # checkout, telemetry and ad-tech endpoints blocked.
  $allowExact = @(
    'static.firestoneapp.com',
    'static.zerotoheroes.com'
  )
  $blocked = New-Object System.Collections.Generic.List[string]
  foreach ($h in ($Hosts | Sort-Object -Unique)) {
    if (-not $h) { continue }
    $hostName = ([string]$h).Trim().ToLowerInvariant()
    $hostName = $hostName -replace '^\*\.',''
    if ($allowExact -contains $hostName) { continue }
    if ($hostName -match 'lambda-url\.us-west-2\.on\.aws$' -or
        $hostName -match '(^|\.)subscriptions-api\.overwolf\.com$' -or
        $hostName -match '(^|\.)checkout\.tebex\.io$' -or
        $hostName -match '(^|\.)api\.overwolf\.com$' -or
        $hostName -match '(^|\.)apps\.overwolf\.com$' -or
        $hostName -match '(^|\.)apps\.overwolfcdn\.com$' -or
        $hostName -match '(^|\.)content\.overwolf\.com$' -or
        $hostName -match '(^|\.)firestoneapp\.com$' -or
        $hostName -match '(^|\.)www\.firestoneapp\.com$' -or
        $hostName -match 'tebex|subscription|checkout|ads?|adnxs|rubicon|pubmatic|sascdn|doubleclick|googlesyndication|amazon-adsystem|id5|arcspan|criteo|seedtag|spotx|yieldmo|openx|smartadserver|scorecardresearch|quantserve|moatads|rlcdn|bidswitch|casalemedia|lijit|sharethrough|undertone|media\.net|improvedigital|triplelift|districtm|gumgum|sonobi|indexexchange|3lift|emxdgt|onetag|33across|adform|adscale|vidazoo|taboola|outbrain|plausible') {
      $blocked.Add($hostName)
    }
  }
  return @($blocked | Sort-Object -Unique)
}

function Get-CurrentShieldHostsBlock {
  $hostsPath = Join-Path $env:SystemRoot 'System32\drivers\etc\hosts'
  if (-not (Test-Path -LiteralPath $hostsPath)) { return @() }
  $content = Get-Content -LiteralPath $hostsPath -Raw -ErrorAction SilentlyContinue
  if ($null -eq $content) { return @() }
  $begin = [regex]::Escape('# Firestone2Green BEGIN')
  $end = [regex]::Escape('# Firestone2Green END')
  $m = [regex]::Match($content, "(?ms)$begin(.*?)$end")
  if (-not $m.Success) { return @() }
  $hosts = New-Object System.Collections.Generic.List[string]
  foreach ($line in ($m.Groups[1].Value -split "`r?`n")) {
    if ($line -match '^\s*0\.0\.0\.0\s+([^\s#]+)') {
      $hosts.Add($Matches[1].ToLowerInvariant())
    }
  }
  return @($hosts | Sort-Object -Unique)
}

function Set-DataOnlineNetwork {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '恢复 Firestone 数据网络并保留云授权/订阅/广告阻断'
  Write-Step '切换到 DataOnline 网络模式'

  # Remove broad program-level deny rules; DataOnline relies on exact hosts
  # blocking so static data endpoints can work.
  $existingRules = @(Get-NetFirewallRule -Group $FirewallGroup -ErrorAction SilentlyContinue)
  if ($existingRules.Count -gt 0) {
    $existingRules | Remove-NetFirewallRule -ErrorAction SilentlyContinue
    Write-Host "已移除程序级全断网防火墙规则：$($existingRules.Count)"
  } else {
    Write-Host '未发现程序级全断网防火墙规则。'
  }

  $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
  $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  if (-not $integrity.ok) {
    throw 'Firestone 签名校验失败，拒绝恢复网络。请先 Restore/Apply。'
  }
  $allHosts = Get-RemoteHostsFromLocalApp -VersionRoot $versionRoot
  $blockedHosts = Get-DataOnlineBlockedHosts -Hosts $allHosts
  Set-HostsBlock -Hosts $blockedHosts
  try { ipconfig /flushdns | Out-Null } catch {}

  Set-State $State 'networkMode' 'DataOnline'
  Set-State $State 'versionRoot' $versionRoot
  Set-State $State 'integrity' $integrity
  Set-State $State 'hostsExtracted' $allHosts
  Set-State $State 'hostsBlocked' $blockedHosts
  Set-State $State 'hostsAllowedForData' @('static.firestoneapp.com','static.zerotoheroes.com')
  Set-State $State 'firewallProgramBlockRemoved' $true
  Write-Host "DataOnline 已启用：阻断 $($blockedHosts.Count) 个风险域名，放行 Firestone 静态数据源。"
}

function Set-AuthOnlyOnlineNetwork {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '恢复全部功能网络，仅保留授权运行时补丁与会员绕过上报阻断'
  Write-Step '切换到 AuthOnlyOnline 网络模式'

  $existingRules = @(Get-NetFirewallRule -Group $FirewallGroup -ErrorAction SilentlyContinue)
  if ($existingRules.Count -gt 0) {
    $existingRules | Remove-NetFirewallRule -ErrorAction SilentlyContinue
    Write-Host "已移除程序级防火墙阻断规则：$($existingRules.Count)"
  } else {
    Write-Host '未发现程序级防火墙阻断规则。'
  }

  $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
  $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  if (-not $integrity.ok) {
    throw 'Firestone 签名校验失败，拒绝恢复网络。请先 Restore/Apply。'
  }

  # Only block the dedicated membership-bypass logging endpoint.
  # This keeps feature Lambdas, account/cloud/deck/community APIs, static data,
  # Overwolf services, and all normal app functionality online.
  $authReportHosts = @(
    '73ybnsv6auhl6x2hv5tvdoppcq0oecmq.lambda-url.us-west-2.on.aws'
  )
  Set-HostsBlock -Hosts $authReportHosts
  try { ipconfig /flushdns | Out-Null } catch {}

  Set-State $State 'networkMode' 'AuthOnlyOnline'
  Set-State $State 'versionRoot' $versionRoot
  Set-State $State 'integrity' $integrity
  Set-State $State 'hostsBlocked' $authReportHosts
  Set-State $State 'firewallProgramBlockRemoved' $true
  Write-Host 'AuthOnlyOnline 已启用：全部功能网络恢复，仅阻断会员绕过上报专用端点。'
}

function Quarantine-Path {
  param([string]$Path, [string]$AllowedRoot, [string]$BackupRoot)
  if (-not (Test-Path -LiteralPath $Path)) { return $null }
  $resolved = Assert-PathUnderRoot -Path $Path -Root $AllowedRoot
  $name = (Split-Path -Leaf $resolved)
  $dest = Join-Path $BackupRoot ("cache_" + (Get-TimeStamp) + "_" + $name)
  if (Test-Path -LiteralPath $dest) {
    $dest = $dest + "_" + ([guid]::NewGuid().ToString('N').Substring(0,6))
  }
  Move-Item -LiteralPath $resolved -Destination $dest -Force
  Write-Host "已隔离缓存：$resolved -> $dest"
  return $dest
}

function Quarantine-FirestoneCaches {
  param([string]$AppId, [string]$BackupRoot)
  Write-Step '隔离云下发/浏览器缓存'
  $cefRoot = Join-Path $env:LOCALAPPDATA 'Overwolf\CefBrowserCache'
  if (-not (Test-Path -LiteralPath $cefRoot)) {
    Write-Host '未找到 CEF 缓存目录。'
    return @()
  }
  $defaultRoot = Join-Path $cefRoot 'Default'
  $targets = @(
    (Join-Path $defaultRoot "IndexedDB\overwolf-extension_${AppId}_0.indexeddb.leveldb"),
    (Join-Path $defaultRoot 'Code Cache\js'),
    (Join-Path $defaultRoot 'Code Cache\wasm'),
    (Join-Path $defaultRoot 'Cache\Cache_Data')
  )
  $moved = New-Object System.Collections.Generic.List[string]
  foreach ($target in $targets) {
    $dest = Quarantine-Path -Path $target -AllowedRoot $cefRoot -BackupRoot $BackupRoot
    if ($dest) { $moved.Add($dest) }
  }
  if ($moved.Count -eq 0) { Write-Host '未发现需要隔离的缓存。' }
  return @($moved)
}

function Get-OverwolfProcessSnapshot {
  $procs = Get-Process -ErrorAction SilentlyContinue | Where-Object {
    $_.ProcessName -like '*Overwolf*' -or
    $_.ProcessName -like 'ow-*' -or
    $_.ProcessName -like '*Firestone*'
  }
  return @($procs | Select-Object Id, ProcessName, Path)
}

function Get-OverwolfTcpSnapshot {
  param([object[]]$Processes)
  if (-not $Processes -or $Processes.Count -eq 0) { return @() }
  $ids = @($Processes | ForEach-Object { $_.Id })
  return @(Get-NetTCPConnection -ErrorAction SilentlyContinue |
    Where-Object { $ids -contains $_.OwningProcess } |
    Select-Object LocalAddress, LocalPort, RemoteAddress, RemotePort, State, OwningProcess)
}

function Get-ExternalTcpSnapshot {
  param([object[]]$TcpRows)
  if (-not $TcpRows) { return @() }
  return @($TcpRows | Where-Object {
    $_.State -ne 'Bound' -and
    $_.RemoteAddress -notin @('127.0.0.1','::1','0.0.0.0','::') -and
    $_.RemoteAddress -notlike '169.254.*' -and
    $_.RemoteAddress -notlike 'fe80:*'
  })
}

function Test-FirewallCoverage {
  param([string]$Group, [string[]]$ExePaths)
  $rulePrograms = @(Get-NetFirewallRule -Group $Group -ErrorAction SilentlyContinue |
    Get-NetFirewallApplicationFilter -ErrorAction SilentlyContinue |
    ForEach-Object { $_.Program })
  $ruleSet = @{}
  foreach ($p in $rulePrograms) { if ($p) { $ruleSet[$p.ToLowerInvariant()] = $true } }
  $missing = @($ExePaths | Where-Object { -not $ruleSet.ContainsKey($_.ToLowerInvariant()) })
  return [pscustomobject]@{
    ruleCount = $rulePrograms.Count
    covered = $missing.Count -eq 0
    missing = $missing
    programs = @($rulePrograms | Sort-Object -Unique)
  }
}

function Write-Report {
  param([System.Collections.IDictionary]$State, [string]$ReportDir)
  New-Directory $ReportDir | Out-Null
  $path = Join-Path $ReportDir ("FirestoneOfflineReport_" + (Get-TimeStamp) + ".json")
  $State | ConvertTo-Json -Depth 8 | Set-Content -LiteralPath $path -Encoding UTF8
  Write-Host "`n报告：$path" -ForegroundColor Green
  return $path
}

function Install-ShieldTask {
  param(
    [string]$TaskName,
    [string]$TaskMode = 'Apply'
  )
  Write-Step "安装计划任务：$TaskName"
  $script = $PSCommandPath
  if (-not $script) { throw '无法确定当前脚本路径，不能安装计划任务。' }
  $rootArg = if (-not [string]::IsNullOrWhiteSpace($OverwolfRoot)) { " -OverwolfRoot `"$OverwolfRoot`"" } else { '' }
  $actionArgs = "-WindowStyle Hidden -NonInteractive -NoLogo -NoProfile -ExecutionPolicy Bypass -File `"$script`" -Mode $TaskMode -AutomationPort $AutomationPort$rootArg -SkipCacheQuarantine"
  $action = New-ScheduledTaskAction -Execute 'powershell.exe' -Argument $actionArgs
  if ($TaskMode -eq 'WatchFirestone') {
    $triggers = @((New-ScheduledTaskTrigger -AtLogOn))
  } else {
    $triggers = @(
      (New-ScheduledTaskTrigger -AtLogOn),
      (New-ScheduledTaskTrigger -Once -At ((Get-Date).AddMinutes(1)) -RepetitionInterval (New-TimeSpan -Minutes 5) -RepetitionDuration (New-TimeSpan -Days 3650))
    )
  }
  $principal = New-ScheduledTaskPrincipal -UserId "$env:USERDOMAIN\$env:USERNAME" -RunLevel Highest -LogonType Interactive
  $settings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -MultipleInstances IgnoreNew -ExecutionTimeLimit (New-TimeSpan -Days 3650)
  Register-ScheduledTask -TaskName $TaskName -Action $action -Trigger $triggers -Principal $principal -Settings $settings -Force | Out-Null
  if ($TaskMode -eq 'WatchFirestone') {
    Write-Host '启动事件监听任务已安装。'
  } else {
    Write-Host '计划任务已安装。'
  }
}

function Install-LaunchTask {
  param(
    [string]$TaskName
  )
  $launchTaskName = "$TaskName Launch"
  Write-Step "安装静默启动任务：$launchTaskName"
  $script = $PSCommandPath
  if (-not $script) { throw '无法确定当前脚本路径，不能安装静默启动任务。' }
  $rootArg = if (-not [string]::IsNullOrWhiteSpace($OverwolfRoot)) { " -OverwolfRoot `"$OverwolfRoot`"" } else { '' }
  $actionArgs = "-WindowStyle Hidden -NonInteractive -NoLogo -NoProfile -ExecutionPolicy Bypass -File `"$script`" -Mode LaunchAuth -AutomationPort $AutomationPort$rootArg -SkipCacheQuarantine"
  $action = New-ScheduledTaskAction -Execute 'powershell.exe' -Argument $actionArgs
  $principal = New-ScheduledTaskPrincipal -UserId "$env:USERDOMAIN\$env:USERNAME" -RunLevel Highest -LogonType Interactive
  $settings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -MultipleInstances IgnoreNew
  Register-ScheduledTask -TaskName $launchTaskName -Action $action -Principal $principal -Settings $settings -Force | Out-Null
  Write-Host '静默启动任务已安装。'
  return $launchTaskName
}

function Install-LaunchShortcut {
  param(
    [string]$Name = 'Firestone2Green 启动 Firestone',
    [string]$TaskName = 'Firestone2Green'
  )
  Write-Step "创建专用启动快捷方式：$Name"
  $script = $PSCommandPath
  if (-not $script) { throw '无法确定当前脚本路径，不能创建快捷方式。' }
  $scriptDir = Split-Path -Parent $script
  $launcherDir = Join-Path ([Environment]::GetFolderPath('LocalApplicationData')) 'Firestone2Green'
  New-Directory $launcherDir | Out-Null
  $launchTaskName = "$TaskName Launch"
  $vbsPath = Join-Path $launcherDir 'LaunchFirestone2Green.vbs'
  $escapedTask = $launchTaskName.Replace('"', '""')
  $vbs = @"
Set sh = CreateObject("WScript.Shell")
sh.Run "schtasks.exe /Run /TN ""$escapedTask""", 0, False
"@
  $vbs | Set-Content -LiteralPath $vbsPath -Encoding ASCII
  $desktop = [Environment]::GetFolderPath('Desktop')
  $shortcutPath = Join-Path $desktop ($Name + '.lnk')
  $shell = New-Object -ComObject WScript.Shell
  $shortcut = $shell.CreateShortcut($shortcutPath)
  $shortcut.TargetPath = 'wscript.exe'
  $shortcut.Arguments = "`"$vbsPath`""
  $shortcut.WorkingDirectory = $scriptDir
  $shortcut.Description = '通过 Firestone2Green 静默启动 Firestone，并自动完成本地授权与网络恢复'
  try {
    $firestoneIcon = Join-Path ([Environment]::GetFolderPath('LocalApplicationData')) "Overwolf\AppShortcutIcons\$AppId.ico"
    if (Test-Path -LiteralPath $firestoneIcon -PathType Leaf) {
      $shortcut.IconLocation = "$firestoneIcon,0"
    } else {
      $launcherIcon = Join-Path $OverwolfRoot 'OverwolfLauncher.exe'
      if (Test-Path -LiteralPath $launcherIcon -PathType Leaf) { $shortcut.IconLocation = "$launcherIcon,0" }
    }
  } catch {}
  $shortcut.Save()
  Write-Host "快捷方式已创建：$shortcutPath"
  Write-Host "静默启动器已创建：$vbsPath"
  return $shortcutPath
}

function Remove-ShieldTask {
  param([string]$TaskName)
  Write-Step "删除计划任务：$TaskName"
  if (Get-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue) {
    try { Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue } catch {}
    Unregister-ScheduledTask -TaskName $TaskName -Confirm:$false
    Write-Host '计划任务已删除。'
  } else {
    Write-Host '计划任务不存在。'
  }
  $launchTaskName = "$TaskName Launch"
  if (Get-ScheduledTask -TaskName $launchTaskName -ErrorAction SilentlyContinue) {
    try { Stop-ScheduledTask -TaskName $launchTaskName -ErrorAction SilentlyContinue } catch {}
    Unregister-ScheduledTask -TaskName $launchTaskName -Confirm:$false
    Write-Host "静默启动任务已删除：$launchTaskName"
  }
  try {
    $shortcutPath = Join-Path ([Environment]::GetFolderPath('Desktop')) 'Firestone2Green 启动 Firestone.lnk'
    if (Test-Path -LiteralPath $shortcutPath) {
      Remove-Item -LiteralPath $shortcutPath -Force
      Write-Host "快捷方式已删除：$shortcutPath"
    }
    $vbsPath = Join-Path ([Environment]::GetFolderPath('LocalApplicationData')) 'Firestone2Green\LaunchFirestone2Green.vbs'
    if (Test-Path -LiteralPath $vbsPath) {
      Remove-Item -LiteralPath $vbsPath -Force
      Write-Host "静默启动器已删除：$vbsPath"
    }
  } catch {
    Write-Warning "快捷方式删除失败：$($_.Exception.Message)"
  }
}

function Invoke-Verify {
  param([System.Collections.IDictionary]$State)
  Write-Step '验证当前离线状态'
  $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
  $versionName = Split-Path -Leaf $versionRoot
  $roots = Get-OverwolfExecutableRoots -OverwolfRoot $OverwolfRoot -CommonOverwolfRoot $CommonOverwolfRoot
  $exes = Get-OverwolfExecutables -Roots $roots
  $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  $coverage = Test-FirewallCoverage -Group $FirewallGroup -ExePaths $exes
  $procs = Get-OverwolfProcessSnapshot
  $tcp = Get-OverwolfTcpSnapshot -Processes $procs
  $externalTcp = Get-ExternalTcpSnapshot -TcpRows $tcp
  $procArray = @()
  foreach ($procItem in $procs) { $procArray += $procItem }
  $tcpArray = @()
  foreach ($tcpItem in $tcp) { $tcpArray += $tcpItem }
  $externalTcpArray = @()
  foreach ($tcpItem in $externalTcp) { $externalTcpArray += $tcpItem }
  $hosts = @()
  if (-not $SkipHosts) { $hosts = Get-RemoteHostsFromLocalApp -VersionRoot $versionRoot }

  Set-State $State 'versionRoot' $versionRoot
  Set-State $State 'version' $versionName
  Set-State $State 'integrity' $integrity
  Set-State $State 'exeRoots' $roots
  Set-State $State 'exeCount' $exes.Count
  Set-State $State 'firewall' $coverage
  Set-State $State 'processes' $procArray
  Set-State $State 'tcp' $tcpArray
  Set-State $State 'externalTcp' $externalTcpArray
  Set-State $State 'hostsExtracted' $hosts
  $currentShieldHosts = Get-CurrentShieldHostsBlock
  $looksLikeDataOnlineHosts = (
    ($currentShieldHosts -contains 'subscriptions-api.overwolf.com') -and
    (-not ($currentShieldHosts -contains 'static.firestoneapp.com')) -and
    (-not ($currentShieldHosts -contains 'static.zerotoheroes.com'))
  )
  $looksLikeAuthOnlyOnlineHosts = (
    ($currentShieldHosts.Count -eq 1) -and
    ($currentShieldHosts -contains '73ybnsv6auhl6x2hv5tvdoppcq0oecmq.lambda-url.us-west-2.on.aws')
  )
  $isAuthOnlyOnline = (($State.Contains('networkMode') -and $State['networkMode'] -eq 'AuthOnlyOnline') -or ($coverage.ruleCount -eq 0 -and $looksLikeAuthOnlyOnlineHosts))
  $isDataOnline = (($State.Contains('networkMode') -and $State['networkMode'] -eq 'DataOnline') -or ($coverage.ruleCount -eq 0 -and $looksLikeDataOnlineHosts))
  $networkPolicyOk = if ($isDataOnline -or $isAuthOnlyOnline) { $true } else { $coverage.covered }
  Set-State $State 'networkPolicyOk' ([bool]$networkPolicyOk)
  $tcpPolicyOk = if ($isDataOnline -or $isAuthOnlyOnline) { $true } else { ($externalTcpArray.Count -eq 0) }
  Set-State $State 'tcpPolicyOk' ([bool]$tcpPolicyOk)
  if ($isDataOnline) { Set-State $State 'networkMode' 'DataOnline' }
  if ($isAuthOnlyOnline) { Set-State $State 'networkMode' 'AuthOnlyOnline' }
  Set-State $State 'ok' ([bool]($integrity.ok -and $networkPolicyOk -and $tcpPolicyOk))

  Write-Host "`n摘要："
  [pscustomobject]@{
    Version = $versionName
    NetworkMode = if ($isAuthOnlyOnline) { 'AuthOnlyOnline' } elseif ($isDataOnline) { 'DataOnline' } else { 'StrictOffline' }
    IntegrityOK = $integrity.ok
    FirewallCovered = $coverage.covered
    FirewallRules = $coverage.ruleCount
    NetworkPolicyOK = $networkPolicyOk
    Processes = $procArray.Count
    TcpConnections = $tcpArray.Count
    TcpExternalConnections = $externalTcpArray.Count
    TcpPolicyOK = $tcpPolicyOk
    OverallOK = $State['ok']
  } | Format-List
}

function Invoke-Apply {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '停止进程、写防火墙/hosts、隔离缓存'
  if (-not $NoKill) { Set-State $State 'stopped' (Stop-OverwolfProcesses) }
  $backupRoot = New-Directory (Join-Path $ReportDir ('backup_' + (Get-TimeStamp)))
  $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
  $versionName = Split-Path -Leaf $versionRoot
  Set-State $State 'versionRootBefore' $versionRoot
  Set-State $State 'version' $versionName
  Set-State $State 'backupRoot' $backupRoot

  $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  if (-not $integrity.ok) {
    Restore-FirestoneFromOpk -VersionRoot $versionRoot -AppId $AppId -BackupRoot $backupRoot
    $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
    $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  }
  Set-State $State 'integrityAfterRestore' $integrity
  Set-State $State 'removedLeftovers' (Remove-KnownPatchLeftovers -VersionRoot $versionRoot)

  if (-not $SkipCacheQuarantine) {
    Set-State $State 'quarantinedCaches' (Quarantine-FirestoneCaches -AppId $AppId -BackupRoot $backupRoot)
  }

  $roots = Get-OverwolfExecutableRoots -OverwolfRoot $OverwolfRoot -CommonOverwolfRoot $CommonOverwolfRoot
  $exes = Get-OverwolfExecutables -Roots $roots
  Set-State $State 'exeRoots' $roots
  Set-State $State 'exePaths' $exes
  Set-State $State 'firewallPrograms' (Set-OverwolfFirewallBlock -Group $FirewallGroup -ExePaths $exes)

  $hosts = Get-RemoteHostsFromLocalApp -VersionRoot $versionRoot
  Set-State $State 'hostsExtracted' $hosts
  if (-not $SkipHosts) {
    Set-HostsBlock -Hosts $hosts
    Set-State $State 'hostsBlocked' $hosts
  }

  Invoke-Verify -State $State
}

function Invoke-Monitor {
  param([System.Collections.IDictionary]$State)
  Write-Step "监控 Overwolf TCP $MonitorSeconds 秒"
  $isDataOnline = ($State.Contains('networkMode') -and $State['networkMode'] -eq 'DataOnline')
  $isAuthOnlyOnline = ($State.Contains('networkMode') -and $State['networkMode'] -eq 'AuthOnlyOnline')
  $events = New-Object System.Collections.Generic.List[object]
  for ($i = 0; $i -lt $MonitorSeconds; $i++) {
    $procs = Get-OverwolfProcessSnapshot
    $tcp = Get-OverwolfTcpSnapshot -Processes $procs
    $externalTcp = Get-ExternalTcpSnapshot -TcpRows $tcp
    if ($externalTcp.Count -gt 0) {
      $events.Add([pscustomobject]@{
        second = $i
        processes = $procs
        tcp = $tcp
        externalTcp = $externalTcp
      })
      if ($isDataOnline -or $isAuthOnlyOnline) {
        Write-Host "$($State['networkMode'])：检测到外网 TCP 记录（允许正常功能网络）：$($externalTcp.Count)"
      } else {
        Write-Warning "检测到 Overwolf 外网 TCP 记录：$($externalTcp.Count)"
        $externalTcp | Format-Table -AutoSize | Out-Host
      }
    }
    Start-Sleep -Seconds 1
  }
  if ($events.Count -eq 0) {
    Write-Host '监控窗口内未发现 Overwolf 外网 TCP 连接。' -ForegroundColor Green
  }
  $eventArray = @()
  foreach ($eventItem in $events) { $eventArray += $eventItem }
  Set-State $State 'monitorEvents' $eventArray
}

function Invoke-AutomationCommand {
  param(
    [int]$Port,
    [string]$CommandId,
    [hashtable]$CommandArgs
  )
  $uri = "http://localhost:$Port/"
  $body = @{ id = $CommandId; args = $CommandArgs } | ConvertTo-Json -Depth 12 -Compress
  return Invoke-RestMethod -Method Post -Uri $uri -Body $body -ContentType 'application/json' -TimeoutSec 20
}

function Wait-AutomationServer {
  param([int]$Port, [int]$TimeoutSeconds = 30)
  Write-Step "等待 Overwolf 本地 automation 接口：http://localhost:$Port/"
  $deadline = (Get-Date).AddSeconds($TimeoutSeconds)
  do {
    try {
      $result = Invoke-AutomationCommand -Port $Port -CommandId 'pingServer' -CommandArgs @{}
      if ($result.success) {
        Write-Host 'automation 接口可用。'
        return $true
      }
    } catch {
      Start-Sleep -Milliseconds 500
    }
  } while ((Get-Date) -lt $deadline)
  throw "automation 接口未在 $TimeoutSeconds 秒内可用：localhost:$Port"
}

function Invoke-FirestoneRuntimeAuth {
  param(
    [System.Collections.IDictionary]$State,
    [int]$Port,
    [string]$AppId,
    [string]$PlanId
  )
  Write-Step "注入 Firestone 本地运行时授权：$PlanId"
  Wait-AutomationServer -Port $Port -TimeoutSeconds 30 | Out-Null

  $plan = [ordered]@{
    id = $PlanId
    active = $true
    autoRenews = $false
    cancelled = $false
    expireAt = '2099-12-31T00:00:00.000Z'
    source = 'Firestone2Green'
  }
  $planJson = ($plan | ConvertTo-Json -Compress)
  $planJsonLiteral = ($planJson | ConvertTo-Json -Compress)

  $script = @'
async function main(){
  const plan = JSON.parse(__PLAN_JSON_LITERAL__);
  const planJson = JSON.stringify(plan);
  const initialAdsService = window.adsService;
  function getAdsService(){ return window.adsService || initialAdsService || null; }
  let a = getAdsService();
  try { if (window.__fsShieldInterval) clearInterval(window.__fsShieldInterval); } catch(e) {}
  try { if (window.__fsShieldLightInterval) clearInterval(window.__fsShieldLightInterval); } catch(e) {}
  window.__fsShieldInterval = null;
  window.__fsShieldLightInterval = null;

  function parseMaybeJson(v){
    if (typeof v !== 'string') return v;
    try { return JSON.parse(v); } catch(e) { return v; }
  }
  function isInactivePlan(v){
    const x = parseMaybeJson(v);
    if (!x || x === 'null' || x === 'undefined') return true;
    if (typeof x === 'string') return x.trim() === '' || x === 'null' || x === 'undefined';
    if (x.active === false || x.active === 0 || x.cancelled === true) return true;
    if (x.expireAt || x.expiresAt || x.expirationDate) {
      const t = Date.parse(x.expireAt || x.expiresAt || x.expirationDate);
      if (!Number.isNaN(t) && t < Date.now()) return true;
    }
    return false;
  }
  function normalizePlanValue(v, asString){
    return isInactivePlan(v) ? (asString ? planJson : plan) : v;
  }

