    if (!subject || subject.__fsShieldPatched) return;
    const orig = subject.next.bind(subject);
    Object.defineProperty(subject, '__fsShieldPatched', { value: true, configurable: false });
    Object.defineProperty(subject, '__fsShieldName', { value: name, configurable: false });
    subject.next = function(v){ return orig(mapper(v)); };
