  patchSubject(a?.currentPlan$$, v => normalizePlanValue(v, false), 'ads.currentPlan');
  patchSubject(a?.hasPremiumSub$$, v => (v === false || v === 0 || v == null ? true : v), 'ads.hasPremium');
  patchSubject(a?.enablePremiumFeatures$$, v => (v === false || v === 0 || v == null ? true : v), 'ads.enablePremium');
  patchSubject(a?.shouldDisplayAds$$, v => false, 'ads.shouldDisplayAds');

  if (a?.subscriptions?.localStorage && !a.subscriptions.localStorage.__fsShieldPatched) {
    const svc = a.subscriptions.localStorage;
    const origSet = svc.setItem?.bind(svc);
    const origGet = svc.getItem?.bind(svc);
    const origRemove = svc.removeItem?.bind(svc);
    Object.defineProperty(svc, '__fsShieldPatched', { value: true, configurable: false });
    if (origSet) svc.setItem = function(k, v){ return origSet(k, k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, false) : v); };
    if (origGet) svc.getItem = function(k){
      const v = origGet(k);
      return k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, false) : v;
    };
    if (origRemove) svc.removeItem = function(k){ if (k === 'CURRENT_SUB_PLAN') return origSet ? origSet(k, plan) : undefined; return origRemove(k); };
  }

  if (!window.__fsShieldStoragePatched) {
    const origLSSet = Storage.prototype.setItem;
    const origLSGet = Storage.prototype.getItem;
    const origLSRemove = Storage.prototype.removeItem;
    const origLSClear = Storage.prototype.clear;
    Object.defineProperty(window, '__fsShieldStoragePatched', { value: true, configurable: false });
    Storage.prototype.setItem = function(k, v){
      return origLSSet.call(this, k, k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, true) : v);
    };
    Storage.prototype.getItem = function(k){
      const v = origLSGet.call(this, k);
      return k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, true) : v;
    };
    Storage.prototype.removeItem = function(k){
      if (k === 'CURRENT_SUB_PLAN') return origLSSet.call(this, k, planJson);
      return origLSRemove.call(this, k);
    };
    Storage.prototype.clear = function(){
      const r = origLSClear.call(this);
      try { origLSSet.call(this, 'CURRENT_SUB_PLAN', planJson); } catch(e) {}
      return r;
    };
  }

  if (a && !a.__fsShieldAdsMethodsPatched) {
    Object.defineProperty(a, '__fsShieldAdsMethodsPatched', { value: true, configurable: false });
    try { a.shouldDisplayAdsInternal = async function(){ return false; }; } catch(e) {}
    try { a.shouldDisplayAds = async function(){ return false; }; } catch(e) {}
    try { a.hasPremiumSub = function(){ return true; }; } catch(e) {}
    try { a.enablePremiumFeatures = function(){ return true; }; } catch(e) {}
  }

  function patchAdsService(svc){
    if (!svc) return;
    patchSubject(svc?.subscriptions?.currentPlan$$, v => normalizePlanValue(v, false), 'subscriptions.currentPlan');
    patchSubject(svc?.currentPlan$$, v => normalizePlanValue(v, false), 'ads.currentPlan');
    patchSubject(svc?.hasPremiumSub$$, v => (v === false || v === 0 || v == null ? true : v), 'ads.hasPremium');
    patchSubject(svc?.enablePremiumFeatures$$, v => (v === false || v === 0 || v == null ? true : v), 'ads.enablePremium');
    patchSubject(svc?.shouldDisplayAds$$, v => false, 'ads.shouldDisplayAds');
    if (svc?.subscriptions?.localStorage && !svc.subscriptions.localStorage.__fsShieldPatched) {
      const storageSvc = svc.subscriptions.localStorage;
      const origSet = storageSvc.setItem?.bind(storageSvc);
      const origGet = storageSvc.getItem?.bind(storageSvc);
      const origRemove = storageSvc.removeItem?.bind(storageSvc);
      Object.defineProperty(storageSvc, '__fsShieldPatched', { value: true, configurable: false });
      if (origSet) storageSvc.setItem = function(k, v){ return origSet(k, k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, false) : v); };
      if (origGet) storageSvc.getItem = function(k){
        const v = origGet(k);
        return k === 'CURRENT_SUB_PLAN' ? normalizePlanValue(v, false) : v;
      };
      if (origRemove) storageSvc.removeItem = function(k){ if (k === 'CURRENT_SUB_PLAN') return origSet ? origSet(k, plan) : undefined; return origRemove(k); };
    }
    if (!svc.__fsShieldAdsMethodsPatched) {
      Object.defineProperty(svc, '__fsShieldAdsMethodsPatched', { value: true, configurable: false });
      try { svc.shouldDisplayAdsInternal = async function(){ return false; }; } catch(e) {}
      try { svc.shouldDisplayAds = async function(){ return false; }; } catch(e) {}
      try { svc.hasPremiumSub = function(){ return true; }; } catch(e) {}
      try { svc.enablePremiumFeatures = function(){ return true; }; } catch(e) {}
    }
  }

  function patchPremiumDom(){
    try {
      if (!document.getElementById('__fsShieldPremiumStyle')) {
        const style = document.createElement('style');
        style.id = '__fsShieldPremiumStyle';
        style.textContent = '.premium-lock{display:none!important}.premium-setting,.premium-setting.locked,.locked{pointer-events:auto!important;opacity:1!important;filter:none!important}.premium-setting.locked{cursor:pointer!important}';
        document.documentElement.appendChild(style);
      }
      document.querySelectorAll('.premium-setting.locked,.locked').forEach(el => { el.classList.remove('locked'); el.classList.add('unlocked'); });
    } catch(e) {}
  }

  function patchAngularAds(){
    const out = { services: 0, premium: 0 };
    try {
      if (!window.ng?.getComponent) return out;
      const seenComponents = new WeakSet();
      const seenServices = new WeakSet();
      const nodes = Array.from(document.querySelectorAll('*')).slice(0, 1200);
      function patchMaybeService(svc){
        if (!svc || typeof svc !== 'object' || seenServices.has(svc)) return;
        if (!svc.hasPremiumSub$$ && !svc.enablePremiumFeatures$$ && !svc.currentPlan$$) return;
        seenServices.add(svc);
        out.services++;
        try { patchAdsService(svc); } catch(e) {}
        try { svc.currentPlan$$?.next(plan); } catch(e) {}
        try { svc.hasPremiumSub$$?.next(true); } catch(e) {}
        try { svc.enablePremiumFeatures$$?.next(true); } catch(e) {}
        if (svc.hasPremiumSub$$?.value === true || svc.enablePremiumFeatures$$?.value === true) out.premium++;
      }
      function patchComponent(cmp){
        if (!cmp || typeof cmp !== 'object' || seenComponents.has(cmp)) return;
        seenComponents.add(cmp);
        patchMaybeService(cmp);
        patchMaybeService(cmp.ads);
        patchMaybeService(cmp.adsService);
        patchMaybeService(cmp.adService);
        try { cmp.premium$$?.next(true); } catch(e) {}
        try { cmp.hasPremiumAccess$$?.next(true); } catch(e) {}
        try { cmp.isPremium$$?.next(true); } catch(e) {}
        try { cmp.cdr?.markForCheck?.(); } catch(e) {}
      }
      for (const node of nodes) {
        try { patchComponent(window.ng.getComponent(node)); } catch(e) {}
        try { patchComponent(window.ng.getOwningComponent?.(node)); } catch(e) {}
      }
    } catch(e) {}
    return out;
  }

  function apply(options){
    const heavy = !!(options && options.heavy);
    a = getAdsService();
    try { patchAdsService(a); } catch(e) {}
    if (heavy || !window.__fsShieldDomPatchDone) {
      try { patchPremiumDom(); window.__fsShieldDomPatchDone = true; } catch(e) {}
    }
    if (heavy || !window.__fsShieldAngularPatchDone) {
      try {
        window.__fsShieldAngularPatch = patchAngularAds();
        if ((window.__fsShieldAngularPatch?.premium || 0) > 0 || (window.__fsShieldAngularPatch?.services || 0) > 0) {
          window.__fsShieldAngularPatchDone = true;
        }
      } catch(e) {}
    }
    try { localStorage.setItem('CURRENT_SUB_PLAN', planJson); } catch(e) {}
    try { a?.subscriptions?.currentPlan$$?.next(plan); } catch(e) {}
    try { a?.currentPlan$$?.next(plan); } catch(e) {}
    try { a?.hasPremiumSub$$?.next(true); } catch(e) {}
    try { a?.enablePremiumFeatures$$?.next(true); } catch(e) {}
    try { a?.shouldDisplayAds$$?.next(false); } catch(e) {}
    try { a?.applyAuthPremiumHint?.(true); } catch(e) {}
  }
  apply({heavy:true});
  let fsShieldReinforceCount = 0;
  window.__fsShieldLightInterval = setInterval(() => {
    fsShieldReinforceCount++;
    apply({heavy:fsShieldReinforceCount <= 8});
    if (fsShieldReinforceCount >= 10) {
      try { clearInterval(window.__fsShieldLightInterval); } catch(e) {}
      window.__fsShieldLightInterval = null;
    }
  }, 2500);
  await new Promise(r => setTimeout(r, 100));
  a = getAdsService();
  const angularPatch = window.__fsShieldAngularPatch || { services: 0, premium: 0 };
  const hasPremiumValue = a ? (a.hasPremiumSub$$?.value === false || a.hasPremiumSub$$?.value === 0 ? true : a.hasPremiumSub$$?.value) : null;
  const enablePremiumValue = a ? (a.enablePremiumFeatures$$?.value === false || a.enablePremiumFeatures$$?.value === 0 ? true : a.enablePremiumFeatures$$?.value) : null;
  const authEffective = (hasPremiumValue === true && enablePremiumValue === true) || angularPatch.premium > 0;
  return {
    ok:true,
    href:location.href,
    title:document.title,
    adsServicePresent:!!a,
    authEffective,
    angularPatch,
    hasPremium:hasPremiumValue,
    enablePremium:enablePremiumValue,
    currentPlan:a?.currentPlan$$?.value,
    subPlan:a?.subscriptions?.currentPlan$$?.value,
    currentSubPlan:localStorage.getItem('CURRENT_SUB_PLAN'),
    shouldDisplayAds:a?.shouldDisplayAdsInternal ? await a.shouldDisplayAdsInternal() : false,
    patched:{
      sub:!!a?.subscriptions?.currentPlan$$?.__fsShieldPatched,
      plan:!!a?.currentPlan$$?.__fsShieldPatched,
      has:!!a?.hasPremiumSub$$?.__fsShieldPatched,
      enable:!!a?.enablePremiumFeatures$$?.__fsShieldPatched,
      serviceStorage:!!a?.subscriptions?.localStorage?.__fsShieldPatched,
      browserStorage:!!window.__fsShieldStoragePatched,
      adsMethods:!!a?.__fsShieldAdsMethodsPatched,
      interval:!!window.__fsShieldLightInterval,
      finiteReinforce:true
    }
  };
}
'@
  $script = $script.Replace('__PLAN_JSON_LITERAL__', $planJsonLiteral)

  $windowIds = @(
    $null,
    "Window_Extension_${AppId}_CollectionWindow",
    "Window_Extension_${AppId}_MainWindow",
    "Window_Extension_${AppId}_SettingsWindow",
    "Window_Extension_${AppId}_LoadingWindow"
  )
  $results = New-Object System.Collections.Generic.List[object]
  $successes = New-Object System.Collections.Generic.List[object]
  foreach ($windowId in $windowIds) {
    $result = $null
    $windowTimeoutSeconds = if ([string]::IsNullOrWhiteSpace($windowId)) { 75 } else { 30 }
    $deadline = (Get-Date).AddSeconds($windowTimeoutSeconds)
    do {
      $args = @{
        uid = $AppId
        script = $script
        entry = 'main'
        timeout = 15000
        entryArgs = '[]'
      }
      if (-not [string]::IsNullOrWhiteSpace($windowId)) { $args.windowId = $windowId }
      $result = Invoke-AutomationCommand -Port $Port -CommandId 'executeScript' -CommandArgs $args
      if ($result.success -and $result.result.ok -and $result.result.authEffective) { break }
      if ($result.success -and $result.result.ok -and -not $result.result.authEffective) {
        Start-Sleep -Seconds 1
        continue
      }
      if ((-not $result.success) -and ([string]$result.error -match "window .+doesn.+t exist")) { break }
      if ($result.result -and $result.result.error -eq 'adsService missing') {
        Start-Sleep -Seconds 1
        continue
      }
      Start-Sleep -Milliseconds 700
    } while ((Get-Date) -lt $deadline)
    $label = if ([string]::IsNullOrWhiteSpace($windowId)) { '(default)' } else { $windowId }
    $row = [pscustomobject]@{ windowId = $label; result = $result }
    $results.Add($row)
    if ($result.success -and $result.result.ok -and $result.result.authEffective) {
      $successes.Add($row)
      Write-Host "授权已注入窗口：$label，hasPremium=$($result.result.hasPremium)，enablePremium=$($result.result.enablePremium)，shouldDisplayAds=$($result.result.shouldDisplayAds)，angular=$($result.result.angularPatch.premium)"
    } elseif ($result.success -and $result.result.ok) {
      Write-Host "窗口已注入基础缓存但授权服务尚未就绪：$label"
    }
  }
  $resultArray = @()
  foreach ($item in $results) { $resultArray += $item }
  Set-State $State 'authResults' $resultArray
  $best = $successes | Where-Object { $_.result.result.adsServicePresent -and $_.result.result.patched.has -and $_.result.result.patched.enable } | Select-Object -First 1
  if (-not $best) { $best = $successes | Where-Object { $_.result.result.angularPatch.premium -gt 0 } | Select-Object -First 1 }
  if (-not $best) { $best = $successes | Where-Object { $_.windowId -like '*CollectionWindow' } | Select-Object -First 1 }
  if (-not $best) { $best = $successes | Select-Object -First 1 }
  if (-not $best) {
    $last = if ($results.Count -gt 0) { $results[$results.Count - 1].result } else { $null }
    Set-State $State 'authResult' $last
    throw "本地授权注入失败：$($last.error) $($last.result.error)"
  }
  $result = $best.result
  Set-State $State 'authResult' $result
  Write-Host "授权状态：hasPremium=$($result.result.hasPremium), enablePremium=$($result.result.enablePremium), shouldDisplayAds=$($result.result.shouldDisplayAds), windows=$($successes.Count)"
  Write-Host '已成功授权：Firestone 本地授权状态已生效。'
  try {
    Invoke-FirestoneAvatarPatch -State $State -Port $Port -AppId $AppId -ImagePath $AvatarImagePath
  } catch {
    Write-Warning "头像补丁未完成：$($_.Exception.Message)"
  }
}

function Get-ImageDataUrl {
  param([string]$ImagePath)
  if (-not [string]::IsNullOrWhiteSpace($ImagePath) -and (Test-Path -LiteralPath $ImagePath)) {
    $ext = [IO.Path]::GetExtension($ImagePath).ToLowerInvariant()
    $mime = switch ($ext) {
      '.png' { 'image/png' }
      '.webp' { 'image/webp' }
      '.gif' { 'image/gif' }
      default { 'image/jpeg' }
    }
    $bytes = [IO.File]::ReadAllBytes((Resolve-Path -LiteralPath $ImagePath).Path)
    return "data:$mime;base64,$([Convert]::ToBase64String($bytes))"
  }
  if (-not [string]::IsNullOrWhiteSpace($Script:EmbeddedAvatarDataUrl)) {
    return $Script:EmbeddedAvatarDataUrl.Trim()
  }
  throw "头像文件不存在且未找到内置头像：$ImagePath"
}

function Invoke-FirestoneAvatarPatch {
  param(
    [System.Collections.IDictionary]$State,
    [int]$Port,
    [string]$AppId,
    [string]$ImagePath
  )
  $dataUrl = Get-ImageDataUrl -ImagePath $ImagePath
  Write-Step "仅替换 Firestone 左下角登录头像"
  $dataUrlLiteral = ($dataUrl | ConvertTo-Json -Compress)
  $script = @'
async function main(){
  const avatarUrl = __AVATAR_DATA_URL__;
  const loginSrcMarker = 'social-share-login';
  const accountRe = /\b(avatar|login|profile|account|user|social|identity)\b/i;
  const strongAccountRe = /\b(login|profile|account|user|social|identity)\b/i;
  const contentRe = /\b(battleground|battlegrounds|bg|hero|heroes|deck|decks|card|cards|environment|archetype|matchup|composition|tier|tier-list|mercenary|mercenaries|minion|minions|trinket|quest|arena|duels|collection|pack|replay|overlay|portrait|tribe|spell|weapon)\b/i;
  function text(v){
    if (v == null) return '';
    if (typeof v === 'string') return v;
    if (typeof v.baseVal === 'string') return v.baseVal;
    return String(v);
  }
  function metaFor(el, depth){
    const parts = [];
    let cur = el;
    for (let i = 0; cur && i < depth; i++, cur = cur.parentElement) {
      parts.push(
        text(cur.className),
        text(cur.id),
        text(cur.getAttribute && cur.getAttribute('aria-label')),
        text(cur.getAttribute && cur.getAttribute('title')),
        text(cur.getAttribute && cur.getAttribute('data-testid')),
        text(cur.getAttribute && cur.getAttribute('routerlink')),
        text(cur.getAttribute && cur.getAttribute('href'))
      );
    }
    return parts.join(' ').toLowerCase();
  }
  function rectInfo(el){
    const r = el.getBoundingClientRect();
    return { left:r.left, top:r.top, right:r.right, bottom:r.bottom, width:r.width, height:r.height };
  }
  function isSmallAvatarRect(r){
    return r.width >= 16 && r.height >= 16 && r.width <= 96 && r.height <= 96;
  }
  function isNearlySquareAvatarRect(r){
    return isSmallAvatarRect(r) && Math.abs(r.width - r.height) <= 8;
  }
  function isBottomLeftLoginRail(r){
    const leftLimit = 90;
    return isSmallAvatarRect(r) &&
      r.left >= -4 &&
      r.left <= leftLimit;
  }
  function srcOf(img){
    return text(img.currentSrc || img.src || img.getAttribute('src')).toLowerCase();
  }
  function isKnownLoginAvatar(img){
    return srcOf(img).includes(loginSrcMarker);
  }
  function isContentArtwork(el){
    const src = (el.tagName === 'IMG' ? srcOf(el) : text(getComputedStyle(el).backgroundImage)).toLowerCase();
    const localMeta = metaFor(el, 6);
    const hasAccountCue = strongAccountRe.test(localMeta) || src.includes(loginSrcMarker);
    const contentSrc = /(?:\/|_|-|\b)(battlegrounds?|heroes?|decks?|cards?|cardart|environment|archetype|minions?|mercenaries|trinkets?|quests?|portraits?|spells?|weapons?)(?:\/|_|-|\.|\b)/i.test(src);
    return (contentSrc || contentRe.test(localMeta)) && !hasAccountCue;
  }
  function shouldPatchImg(img){
    if (!img) return false;
    const r = rectInfo(img);
    if (!isBottomLeftLoginRail(r)) return false;
    if (isContentArtwork(img)) return false;
    const meta = metaFor(img, 5);
    return isKnownLoginAvatar(img) || srcOf(img) === avatarUrl.toLowerCase() || accountRe.test(meta);
  }
  function shouldPatchBox(el){
    if (!el || el.tagName === 'IMG') return false;
    const r = rectInfo(el);
    if (!isBottomLeftLoginRail(r)) return false;
    if (!isNearlySquareAvatarRect(r)) return false;
    if (el.querySelector && el.querySelector('img')) return false;
    if (isContentArtwork(el)) return false;
    const bg = text(getComputedStyle(el).backgroundImage).toLowerCase();
    const meta = metaFor(el, 5);
    return bg.includes(loginSrcMarker) || bg.includes(avatarUrl.slice(0, 64).toLowerCase()) || accountRe.test(meta);
  }
  function cleanupStretchedAvatarBackgrounds(targetImgs){
    let cleaned = 0;
    const seen = new Set();
    const candidates = Array.from(document.querySelectorAll('.avatar, [class*="avatar"], [class*="login"], [class*="profile"], [class*="account"], [class*="user"], [style*="data:image"]'));
    for (const img of targetImgs || []) {
      let cur = img.parentElement;
      for (let i = 0; cur && i < 4; i++, cur = cur.parentElement) candidates.push(cur);
    }
    for (const el of candidates) {
      if (!el || el.tagName === 'IMG' || seen.has(el)) continue;
      seen.add(el);
      const r = rectInfo(el);
      if (!isBottomLeftLoginRail(r)) continue;
      if (isNearlySquareAvatarRect(r)) continue;
      const inlineBg = text(el.style && el.style.backgroundImage).toLowerCase();
      const computedBg = text(getComputedStyle(el).backgroundImage).toLowerCase();
      if (inlineBg.includes('data:image') || inlineBg.includes(avatarUrl.slice(0, 64).toLowerCase()) || computedBg.includes(avatarUrl.slice(0, 64).toLowerCase())) {
        el.style.backgroundImage = 'none';
        el.style.backgroundSize = '';
        el.style.backgroundPosition = '';
        el.style.borderRadius = '';
        cleaned++;
      }
    }
    return cleaned;
  }
  function patchOnce(){
    const stats = {
      patched: 0,
      candidateCount: 0,
      skippedContentCount: 0,
      patchedRects: [],
      targetRects: []
    };
    const allImages = Array.from(document.images);
    stats.skippedContentCount = allImages.filter(img => isSmallAvatarRect(rectInfo(img)) && isContentArtwork(img)).length;
    const imgs = allImages.filter(img => {
      const match = shouldPatchImg(img);
      if (match) stats.candidateCount++;
      return match;
    });
    for (const img of imgs) {
      if (img.src !== avatarUrl) {
        img.src = avatarUrl;
        img.removeAttribute('srcset');
        img.referrerPolicy = 'no-referrer';
        stats.patched++;
      }
      img.style.objectFit = 'cover';
      img.style.borderRadius = '50%';
      img.style.aspectRatio = '1 / 1';
      img.style.display = 'block';
      const r = rectInfo(img);
      stats.targetRects.push(r);
      stats.patchedRects.push(r);
    }
    stats.cleanedStretchedContainers = cleanupStretchedAvatarBackgrounds(imgs);
    const avatarBoxes = Array.from(document.querySelectorAll('.avatar, [class*="avatar"], [class*="login"], [class*="profile"], [class*="account"], [class*="user"], [style*="social-share-login"]'))
      .filter(shouldPatchBox);
    stats.candidateCount += avatarBoxes.length;
    for (const el of avatarBoxes) {
      el.style.backgroundImage = `url("${avatarUrl}")`;
      el.style.backgroundSize = 'cover';
      el.style.backgroundPosition = 'center';
      el.style.borderRadius = '50%';
      stats.patched++;
      const r = rectInfo(el);
      stats.targetRects.push(r);
      stats.patchedRects.push(r);
    }
    stats.currentTargetMatches = allImages.filter(shouldPatchImg).length;
    stats.currentAvatarUrlMatches = allImages.filter(img => img.src === avatarUrl).length;
    stats.leakedAvatarUrlMatches = allImages.filter(img => img.src === avatarUrl && !shouldPatchImg(img)).length;
    window.__fsShieldAvatarLastStats = stats;
    return stats;
  }
  try { if (window.__fsShieldAvatarInterval) clearInterval(window.__fsShieldAvatarInterval); } catch(e) {}
  try { if (window.__fsShieldAvatarObserver) window.__fsShieldAvatarObserver.disconnect(); } catch(e) {}
  window.__fsShieldAvatarInterval = null;
  window.__fsShieldAvatarObserver = null;
  window.__fsShieldAvatarScheduled = false;
  const first = patchOnce();
  let avatarRetryCount = 0;
  window.__fsShieldAvatarInterval = setInterval(() => {
    avatarRetryCount++;
    patchOnce();
    if (avatarRetryCount >= 10) {
      try { clearInterval(window.__fsShieldAvatarInterval); } catch(e) {}
      window.__fsShieldAvatarInterval = null;
    }
  }, 1000);
  await new Promise(r => setTimeout(r, 180));
  const latest = window.__fsShieldAvatarLastStats || first;
  return {
    ok:true,
    href:location.href,
    title:document.title,
    firstPatched:first.patched,
    patched:latest.patched,
    candidateCount:latest.candidateCount,
    skippedContentCount:latest.skippedContentCount,
    cleanedStretchedContainers:latest.cleanedStretchedContainers,
    currentMatches:latest.currentAvatarUrlMatches,
    currentTargetMatches:latest.currentTargetMatches,
    leakedAvatarUrlMatches:latest.leakedAvatarUrlMatches,
    patchedRects:latest.patchedRects,
    interval:!!window.__fsShieldAvatarInterval,
    observer:false,
    finiteRetry:true
  };
}
'@
  $script = $script.Replace('__AVATAR_DATA_URL__', $dataUrlLiteral)
  $windowIds = @(
    "Window_Extension_${AppId}_CollectionWindow",
    "Window_Extension_${AppId}_MainWindow",
    "Window_Extension_${AppId}_SettingsWindow",
    "Window_Extension_${AppId}_LoadingWindow"
  )
  $results = New-Object System.Collections.Generic.List[object]
  foreach ($windowId in $windowIds) {
    try {
      $result = Invoke-AutomationCommand -Port $Port -CommandId 'executeScript' -CommandArgs @{
        uid = $AppId
        script = $script
        entry = 'main'
        timeout = 10000
        entryArgs = '[]'
        windowId = $windowId
      }
      $results.Add([pscustomobject]@{ windowId = $windowId; result = $result })
      if ($result.success -and $result.result.ok) {
        Write-Host "头像已注入窗口：$windowId，目标数=$($result.result.currentTargetMatches)，全局命中=$($result.result.currentMatches)，误命中=$($result.result.leakedAvatarUrlMatches)"
      }
    } catch {
      $results.Add([pscustomobject]@{ windowId = $windowId; error = $_.Exception.Message })
    }
  }
  $resultArray = @()
  foreach ($item in $results) { $resultArray += $item }
  Set-State $State 'avatarPatch' $resultArray
}

function Get-FirestoneAppProcesses {
  param([string]$AppId)
  $rows = @()
  try {
    $rows = @(Get-CimInstance Win32_Process -ErrorAction SilentlyContinue | Where-Object {
      $name = [IO.Path]::GetFileNameWithoutExtension([string]$_.Name)
      $cmd = [string]$_.CommandLine
      if ($name -eq 'Firestone2Green') { return $false }
      $isOverwolfProcess = ($name -like '*Overwolf*' -or $name -like 'ow-*')
      $isFirestoneProcess = ($cmd -like "*$AppId*" -or $cmd -like '*Firestone - *')
      $isOverwolfProcess -and $isFirestoneProcess
    } | Select-Object ProcessId, Name, CommandLine)
  } catch {
    $rows = @()
  }
  return @($rows)
}

function Test-AutomationServerReady {
  param([int]$Port)
  try {
    $result = Invoke-AutomationCommand -Port $Port -CommandId 'pingServer' -CommandArgs @{}
    return [bool]($result.success)
  } catch {
    return $false
  }
}

function Start-FirestoneLaunchWithFallback {
  param(
    [System.Collections.IDictionary]$State,
    [string]$Launcher,
    [int]$Port
  )

  $attempts = @()
  $candidates = @(
    [pscustomobject]@{
      Name = '兼容旧式启动：-launchapp -from-desktop + automation'
      Args = @('-launchapp', $AppId, '-from-desktop', '--automation', "$Port", '--enable-automation')
      TimeoutSeconds = 30
    },
    [pscustomobject]@{
      Name = '新版启动：--launchapp --origin desktop + automation'
      Args = @('--launchapp', $AppId, '--origin', 'desktop', '--automation', "$Port", '--enable-automation')
      TimeoutSeconds = 30
    },
    [pscustomobject]@{
      Name = '混合启动：-launchapp --origin desktop + automation'
      Args = @('-launchapp', $AppId, '--origin', 'desktop', '--automation', "$Port", '--enable-automation')
      TimeoutSeconds = 20
    }
  )

  for ($i = 0; $i -lt $candidates.Count; $i++) {
    $candidate = $candidates[$i]
    Write-Step ("启动方式 {0}/{1}：{2}" -f ($i + 1), $candidates.Count, $candidate.Name)
    $record = [ordered]@{
      index = ($i + 1)
      name = $candidate.Name
      args = ($candidate.Args -join ' ')
      startedAt = (Get-Date).ToString('o')
      automationReady = $false
      firestoneProcessCount = 0
    }
    $recordAdded = $false
    try {
      Start-Process -FilePath $Launcher -ArgumentList $candidate.Args
      $deadline = (Get-Date).AddSeconds([int]$candidate.TimeoutSeconds)
      do {
        if (Test-AutomationServerReady -Port $Port) {
          $record['automationReady'] = $true
          $record['completedAt'] = (Get-Date).ToString('o')
          $attempts += [pscustomobject]$record
          $recordAdded = $true
          Set-State $State 'launchAttempts' $attempts
          Set-State $State 'selectedLaunchMode' $candidate.Name
          Write-Host 'automation 接口可用。'
          return $candidate.Name
        }
        Start-Sleep -Milliseconds 500
      } while ((Get-Date) -lt $deadline)

      $running = @(Get-FirestoneAppProcesses -AppId $AppId)
      $record['firestoneProcessCount'] = $running.Count
      $record['error'] = "automation 接口未在 $($candidate.TimeoutSeconds) 秒内可用"
      Write-Warning ("{0} 未打开 automation，准备切换下一种启动方式。" -f $candidate.Name)
    } catch {
      $record['error'] = $_.Exception.Message
      Write-Warning ("{0} 启动失败：{1}" -f $candidate.Name, $_.Exception.Message)
    } finally {
      if (-not $record.Contains('completedAt')) { $record['completedAt'] = (Get-Date).ToString('o') }
      if (-not $recordAdded) {
        $attempts += [pscustomobject]$record
        Set-State $State 'launchAttempts' $attempts
      }
    }

    if (($i -lt ($candidates.Count - 1)) -and -not $NoKill) {
      Write-Host '清理上一次未成功开启 automation 的 Overwolf/Firestone 进程后重试。'
      Stop-OverwolfProcesses | Out-Null
      Start-Sleep -Seconds 2
    }
  }

  Write-Warning '所有 automation 启动方式都失败，改用普通方式打开 Firestone，避免快捷方式看起来“无响应”。'
  try {
    Start-Process -FilePath $Launcher -ArgumentList @('-launchapp', $AppId, '-from-desktop')
  } catch {
    Write-Warning "普通启动也失败：$($_.Exception.Message)"
  }
  Set-State $State 'automationAvailable' $false
  throw 'automation 接口不可用：已尝试旧式/新版/混合启动参数。请先确认 Firestone 已在 Overwolf 中安装并能正常打开；升级后如已安装持续修复，请先“移除持续修复”再“安装持续修复”。'
}

function Start-FirestoneWithAutomation {
  param(
    [System.Collections.IDictionary]$State,
    [switch]$RestartExisting,
    [switch]$SkipMonitor
  )
  $launcher = Get-OverwolfLauncherPath
  if ($RestartExisting -and -not $NoKill) {
    Write-Step '检测到 Firestone 已运行但未开启 automation，自动重启并补授权'
    Set-State $State 'autoRestartStopped' (Stop-OverwolfProcesses)
  }
  Write-Step "启动 Firestone，并开启本地 automation 端口 $AutomationPort"
  Start-FirestoneLaunchWithFallback -State $State -Launcher $launcher -Port $AutomationPort | Out-Null
  Start-Sleep -Seconds 3
  Set-AuthOnlyOnlineNetwork -State $State
  Invoke-FirestoneRuntimeAuth -State $State -Port $AutomationPort -AppId $AppId -PlanId $AuthPlanId
  Set-State $State 'networkMode' 'AuthOnlyOnline'
  Set-State $State 'automationAvailable' $true
  if (-not $SkipMonitor) { Invoke-Monitor -State $State }
}

function Invoke-Launch {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '启动前确保阻断规则已应用'
  Invoke-Apply -State $State
  $launcher = Get-OverwolfLauncherPath
  Write-Step '在离线阻断已生效后启动 Firestone'
  Start-Process -FilePath $launcher -ArgumentList @('-launchapp', $AppId, '-from-desktop')
  Start-Sleep -Seconds 3
  Invoke-Monitor -State $State
}

function Invoke-PrepareLaunchAuth {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '启动前校验本地包，并提前恢复全功能数据网络'
  if (-not $NoKill) { Set-State $State 'stopped' (Stop-OverwolfProcesses) }
  $backupRoot = New-Directory (Join-Path $ReportDir ('backup_' + (Get-TimeStamp)))
  $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
  $versionName = Split-Path -Leaf $versionRoot
  Set-State $State 'versionRootBefore' $versionRoot
  Set-State $State 'version' $versionName
  Set-State $State 'backupRoot' $backupRoot

  $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  if (-not $integrity.ok) {
    Restore-FirestoneFromOpk -VersionRoot $versionRoot -AppId $AppId -BackupRoot $backupRoot
    $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
    $integrity = Test-FirestoneIntegrity -VersionRoot $versionRoot
  }
  Set-State $State 'integrityAfterRestore' $integrity
  Set-State $State 'removedLeftovers' (Remove-KnownPatchLeftovers -VersionRoot $versionRoot)

  if (-not $SkipCacheQuarantine) {
    Set-State $State 'quarantinedCaches' (Quarantine-FirestoneCaches -AppId $AppId -BackupRoot $backupRoot)
  }

  # 关键修复：启动 Firestone 前就切到 AuthOnlyOnline。
  # 旧流程会先全断网启动，再授权后恢复网络；套牌/环境数据有时会在断网窗口初始化失败。
  Set-AuthOnlyOnlineNetwork -State $State
  Set-State $State 'networkMode' 'AuthOnlyOnline'
}

function Invoke-LaunchAuth {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '启动前确保本地包完整，并打开本地 automation 接口'
  $prepared = $false
  try {
    Invoke-PrepareLaunchAuth -State $State
    $prepared = $true
    Start-FirestoneWithAutomation -State $State
  } catch {
    if ($prepared) {
      try {
        Write-Warning '启动/授权流程未完成，正在恢复 AuthOnlyOnline 网络模式，避免套牌/数据网络停留在异常状态。'
        Set-AuthOnlyOnlineNetwork -State $State
      } catch {
        Write-Warning "网络恢复失败：$($_.Exception.Message)"
      }
    }
    throw
  }
}

function Invoke-AutoAuth {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '持续修复需要维持网络规则，并在 automation 可用时刷新授权'
  Set-AuthOnlyOnlineNetwork -State $State
  Set-State $State 'networkMode' 'AuthOnlyOnline'
  try {
    Wait-AutomationServer -Port $AutomationPort -TimeoutSeconds 5 | Out-Null
    Set-State $State 'automationAvailable' $true
    Invoke-FirestoneRuntimeAuth -State $State -Port $AutomationPort -AppId $AppId -PlanId $AuthPlanId
  } catch {
    Set-State $State 'automationAvailable' $false
    Set-State $State 'authSkippedReason' $_.Exception.Message
    $runningFirestone = @(Get-FirestoneAppProcesses -AppId $AppId)
    Set-State $State 'detectedFirestoneProcessCount' $runningFirestone.Count
    if ($runningFirestone.Count -gt 0) {
      Set-State $State 'detectedFirestoneProcesses' $runningFirestone
      Write-Host "持续修复：检测到 Firestone 已运行但 automation 端口不可用，正在静默重启并补授权。"
      Start-FirestoneWithAutomation -State $State -RestartExisting -SkipMonitor
    } else {
      Write-Host "持续修复：网络规则已维持；当前 Firestone 未运行或 automation 端口不可用。下次启动后会自动检查并补授权。"
    }
  }
}

function Test-FirestoneStartupEvent {
  param(
    [int]$ProcessId,
    [string]$ProcessName,
    [string]$AppId
  )
  if ([string]::IsNullOrWhiteSpace($ProcessName)) { return $false }
  if ($ProcessName -ieq 'Firestone2Green.exe') { return $false }
  if ($ProcessName -notin @('Overwolf.exe','OverwolfLauncher.exe')) { return $false }
  Start-Sleep -Milliseconds 500
  try {
    $proc = Get-CimInstance Win32_Process -Filter "ProcessId=$ProcessId" -ErrorAction SilentlyContinue
    if ($proc) {
      $cmd = [string]$proc.CommandLine
      if ($cmd -like '*--automation*' -or $cmd -like '*--enable-automation*') { return $false }
      $isLaunchCommand = ($cmd -match '(?i)(^|\\s)-{1,2}launchapp(\\s|=)') -or ($cmd -like '*-from-desktop*') -or ($cmd -like '*--origin desktop*')
      if (($cmd -like "*$AppId*") -and $isLaunchCommand) { return $true }
    }
  } catch {}
  return $false
}

function Invoke-WatchAuthOnce {
  param(
    [System.Collections.IDictionary]$State,
    [string]$Reason
  )
  if ($Script:FirestoneWatchBusy) { return }
  $now = Get-Date
  if ($Script:FirestoneWatchLastAttempt -and (($now - $Script:FirestoneWatchLastAttempt).TotalSeconds -lt 20)) {
    return
  }
  $Script:FirestoneWatchBusy = $true
  $Script:FirestoneWatchLastAttempt = $now
  try {
    Write-Step "检测到 Firestone 启动：$Reason"
    Invoke-AutoAuth -State $State
  } catch {
    Set-State $State 'lastWatchError' $_.Exception.Message
    Write-Warning "事件授权失败：$($_.Exception.Message)"
    try {
      Set-AuthOnlyOnlineNetwork -State $State
    } catch {
      Write-Warning "事件失败后的网络恢复失败：$($_.Exception.Message)"
    }
  } finally {
    $Script:FirestoneWatchBusy = $false
  }
}

function Invoke-WatchFirestoneStartup {
  param([System.Collections.IDictionary]$State)
  Assert-Admin '持续修复事件监听需要最高权限'
  Set-State $State 'watchMode' 'WmiProcessStartTrace'
  Set-State $State 'watchStartedAt' ((Get-Date).ToString('o'))
  try {
    Set-AuthOnlyOnlineNetwork -State $State
    Set-State $State 'networkMode' 'AuthOnlyOnline'
  } catch {
    Set-State $State 'initialNetworkError' $_.Exception.Message
    Write-Warning "启动监听前的网络模式初始化失败：$($_.Exception.Message)"
  }

  $source = 'Firestone2GreenProcessStart'
  try { Unregister-Event -SourceIdentifier $source -ErrorAction SilentlyContinue } catch {}
  try { Remove-Event -SourceIdentifier $source -ErrorAction SilentlyContinue } catch {}
  $query = "SELECT * FROM Win32_ProcessStartTrace WHERE ProcessName = 'Overwolf.exe' OR ProcessName = 'OverwolfLauncher.exe'"
  Register-WmiEvent -Query $query -SourceIdentifier $source | Out-Null
  Write-Host '已进入 Firestone 手动启动事件监听模式：只有检测到 -launchapp 启动 Firestone 时才会静默补授权，不会主动拉起 Firestone。'
  try {
    while ($true) {
      $evt = Wait-Event -SourceIdentifier $source -Timeout 3600
      if (-not $evt) { continue }
      try {
        $eventProcess = $evt.SourceEventArgs.NewEvent
        $pid = [int]$eventProcess.ProcessID
        $pname = [string]$eventProcess.ProcessName
        Remove-Event -EventIdentifier $evt.EventIdentifier -ErrorAction SilentlyContinue
        if (Test-FirestoneStartupEvent -ProcessId $pid -ProcessName $pname -AppId $AppId) {
          Invoke-WatchAuthOnce -State $State -Reason "$pname/$pid"
        }
      } catch {
        Set-State $State 'lastWatchLoopError' $_.Exception.Message
        Write-Warning "事件处理失败：$($_.Exception.Message)"
      }
    }
  } finally {
    try { Unregister-Event -SourceIdentifier $source -ErrorAction SilentlyContinue } catch {}
    try { Remove-Event -SourceIdentifier $source -ErrorAction SilentlyContinue } catch {}
  }
}



$state = [ordered]@{
  startedAt = (Get-Date).ToString('o')
  mode = $Mode
  appId = $AppId
  appName = $AppName
  overwolfRoot = $OverwolfRoot
  script = $PSCommandPath
  user = "$env:USERDOMAIN\$env:USERNAME"
  computer = $env:COMPUTERNAME
}

try {
  switch ($Mode) {
    'Apply' {
      Invoke-Apply -State $state
    }
    'Verify' {
      Invoke-Verify -State $state
    }
    'Restore' {
      Assert-Admin '恢复签名包'
      if (-not $NoKill) { Set-State $state 'stopped' (Stop-OverwolfProcesses) }
      $backupRoot = New-Directory (Join-Path $ReportDir ('backup_' + (Get-TimeStamp)))
      $versionRoot = Get-FirestoneVersionRoot -AppId $AppId
      Restore-FirestoneFromOpk -VersionRoot $versionRoot -AppId $AppId -BackupRoot $backupRoot
      Invoke-Verify -State $state
    }
    'Monitor' {
      Invoke-Monitor -State $state
    }
    'Launch' {
      Invoke-Launch -State $state
    }
    'Auth' {
      Invoke-FirestoneRuntimeAuth -State $state -Port $AutomationPort -AppId $AppId -PlanId $AuthPlanId
    }
    'LaunchAuth' {
      Invoke-LaunchAuth -State $state
    }
    'AutoAuth' {
      Invoke-AutoAuth -State $state
    }
    'WatchFirestone' {
      Invoke-WatchFirestoneStartup -State $state
    }
    'DataOnline' {
      Set-DataOnlineNetwork -State $state
      Invoke-Verify -State $state
    }
    'AuthOnlyOnline' {
      Set-AuthOnlyOnlineNetwork -State $state
      Invoke-Verify -State $state
    }
    'InstallTask' {
      Assert-Admin '安装最高权限计划任务'
      Install-ShieldTask -TaskName $TaskName -TaskMode 'Apply'
      Invoke-Verify -State $state
    }
    'InstallDataOnlineTask' {
      Assert-Admin '安装 DataOnline 持久计划任务'
      Install-ShieldTask -TaskName $TaskName -TaskMode 'DataOnline'
      Set-State $state 'networkMode' 'DataOnline'
      Invoke-Verify -State $state
    }
    'InstallAuthOnlyOnlineTask' {
      Assert-Admin '安装 AuthOnlyOnline 持久计划任务'
      Install-ShieldTask -TaskName $TaskName -TaskMode 'AuthOnlyOnline'
      Set-State $state 'networkMode' 'AuthOnlyOnline'
      Invoke-Verify -State $state
    }
    'InstallAutoAuthTask' {
      Assert-Admin '安装 Firestone2Green 持续授权修复'
      Install-ShieldTask -TaskName $TaskName -TaskMode 'WatchFirestone'
      Set-State $state 'launchTask' (Install-LaunchTask -TaskName $TaskName)
      Set-State $state 'launchShortcut' (Install-LaunchShortcut -TaskName $TaskName)
      Set-AuthOnlyOnlineNetwork -State $state
      Set-State $state 'networkMode' 'AuthOnlyOnline'
      try {
        $watchTask = Get-ScheduledTask -TaskName $TaskName -ErrorAction Stop
        if ($watchTask.State -eq 'Running') {
          Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
          $deadline = (Get-Date).AddSeconds(8)
          do {
            Start-Sleep -Milliseconds 250
            $watchTask = Get-ScheduledTask -TaskName $TaskName -ErrorAction Stop
          } while ($watchTask.State -eq 'Running' -and (Get-Date) -lt $deadline)
          Set-State $state 'watchTaskWasRunning' $true
        }
        Start-ScheduledTask -TaskName $TaskName -ErrorAction Stop
        Set-State $state 'watchTaskStarted' $true
        Set-State $state 'watchTaskRestarted' $true
      } catch {
        Set-State $state 'watchTaskStarted' $false
        Set-State $state 'watchTaskStartError' $_.Exception.Message
      }
      Write-Host '持续修复已安装：已改为 Firestone 启动事件监听，不再按固定时间轮询，也不会主动启动 Firestone。需要立即授权时请点击“一键重启并授权”，以后建议使用桌面“Firestone2Green 启动 Firestone”快捷方式。'
      Invoke-Verify -State $state
    }
    'RemoveTask' {
      Assert-Admin '删除计划任务'
      Remove-ShieldTask -TaskName $TaskName
      Invoke-Verify -State $state
    }
    'All' {
      Invoke-Apply -State $state
      Assert-Admin '安装最高权限计划任务'
      Install-ShieldTask -TaskName $TaskName
    }
  }
  Set-State $state 'finishedAt' ((Get-Date).ToString('o'))
  Set-State $state 'error' $null
} catch {
  Set-State $state 'finishedAt' ((Get-Date).ToString('o'))
  Set-State $state 'error' $_.Exception.Message
  Set-State $state 'errorType' ($_.Exception.GetType().FullName)
  Set-State $state 'errorLine' $_.InvocationInfo.ScriptLineNumber
  Set-State $state 'errorCommand' $_.InvocationInfo.Line
  Set-State $state 'errorStack' $_.ScriptStackTrace
  Write-Host "错误位置：line $($state['errorLine'])" -ForegroundColor Red
  Write-Host $state['errorCommand'] -ForegroundColor Red
  Write-Host $state['errorStack'] -ForegroundColor DarkRed
  Write-Error $_
} finally {
  try { Write-Report -State $state -ReportDir $ReportDir | Out-Null } catch { Write-Warning "报告写入失败：$($_.Exception.Message)" }
}

if ($state['error']) { exit 1 }
if ($state.Contains('ok') -and -not $state['ok']) { exit 2 }
exit 0
